-- ============================================================================
-- Quiz Seed: Ezra (Chapters 1–10)
-- 3 difficulties × 10 chapters = 160 total questions
-- kids: 3 per chapter, teens: 5 per chapter, adults: 8 per chapter
-- ============================================================================

-- ═══ Ezra Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 1, 'kids', 1, 'Which king made a decree that God''s people could go back to Jerusalem to build the temple?', 'King Cyrus of Persia', 'King Darius of Babylon', 'King Artaxerxes of Media', 'King Nebuchadnezzar of Assyria', 'a', 'Ezra 1:1 — "Now in the first year of Cyrus king of Persia...the LORD stirred up the spirit of Cyrus king of Persia, that he made a proclamation throughout all his kingdom."'),
('Ezra', 1, 'kids', 2, 'What did Cyrus say the people going to Jerusalem should build?', 'A house for God in Jerusalem', 'A wall around the city', 'A palace for the priests', 'A road back to Israel', 'a', 'Ezra 1:3 — "Whosoever there is among you of all his people...let him go up to Jerusalem, which is in Judah, and build the house of the LORD God of Israel."'),
('Ezra', 1, 'kids', 3, 'What precious items did Cyrus bring out to give back to the returning people?', 'The vessels of the house of the LORD that Nebuchadnezzar had taken from Jerusalem', 'Gold coins from the Persian treasury', 'Silver cups from the king''s own table', 'Bronze tools for building the temple', 'a', 'Ezra 1:7 — "Also Cyrus the king brought forth the vessels of the house of the LORD, which Nebuchadnezzar had brought forth out of Jerusalem."'),
-- Teens
('Ezra', 1, 'teens', 1, 'How does Ezra 1:1 say the prophet Jeremiah''s words were fulfilled through Cyrus''s decree?', 'The LORD stirred up the spirit of Cyrus so that the seventy years of captivity Jeremiah foretold would be completed', 'Jeremiah had written a letter to Cyrus telling him to release the captives', 'Cyrus read the book of Jeremiah and decided to free the people out of reverence', 'God sent Jeremiah himself to Cyrus as an ambassador to negotiate the return', 'a', 'Ezra 1:1 — "Now in the first year of Cyrus king of Persia, that the word of the LORD by the mouth of Jeremiah might be fulfilled, the LORD stirred up the spirit of Cyrus king of Persia."'),
('Ezra', 1, 'teens', 2, 'What did Cyrus''s proclamation say about God''s relationship to him and his command to build the temple?', 'The LORD God of heaven hath given me all the kingdoms of the earth and hath charged me to build him an house at Jerusalem', 'The god of the Persians hath blessed me and I give thanks by freeing the Hebrews', 'Marduk the great god hath spoken to me and commanded me to restore Jerusalem', 'The stars of heaven have shown me that the Hebrews must return to their land', 'a', 'Ezra 1:2 — "Thus saith Cyrus king of Persia, The LORD God of heaven hath given me all the kingdoms of the earth; and he hath charged me to build him an house at Jerusalem, which is in Judah."'),
('Ezra', 1, 'teens', 3, 'What were the neighbours of the returning exiles asked to give them for the journey?', 'Silver, gold, goods, beasts, and freewill offerings for the house of God', 'Food and water for the long road back to Israel', 'Horses and chariots for the families to travel safely', 'Tents and tools to set up camp along the way', 'a', 'Ezra 1:4 — "And whosoever remaineth in any place where he sojourneth, let the men of his place help him with silver, and with gold, and with goods, and with beasts, beside the freewill offering for the house of God that is in Jerusalem."'),
('Ezra', 1, 'teens', 4, 'Who was the prince of Judah that Cyrus entrusted with the temple vessels to bring back to Jerusalem?', 'Sheshbazzar', 'Zerubbabel', 'Jeshua', 'Nehemiah', 'a', 'Ezra 1:8 — "Even those did Cyrus king of Persia bring forth by the hand of Mithredath the treasurer, and numbered them unto Sheshbazzar, the prince of Judah."'),
('Ezra', 1, 'teens', 5, 'How many total vessels of gold and silver are mentioned in Cyrus''s return of temple treasures?', 'Five thousand and four hundred', 'Three thousand and three hundred', 'Seven thousand and seven', 'Two thousand four hundred and ten', 'a', 'Ezra 1:11 — "All the vessels of gold and of silver were five thousand and four hundred. All these did Sheshbazzar bring up with them of the captivity that were brought up from Babylon unto Jerusalem."'),
-- Adults
('Ezra', 1, 'adults', 1, 'What does the phrase "the LORD stirred up the spirit of Cyrus" in Ezra 1:1 reveal about the theological perspective of the author?', 'It shows that God sovereignly works through pagan rulers to fulfil his covenant promises, directing their hearts without removing their agency', 'It implies Cyrus was secretly a worshipper of Yahweh who converted before issuing the decree', 'It means Cyrus was possessed by the Spirit of God in the same manner as an Israelite prophet', 'It shows the author believed Persian kings were instruments of fate rather than personal divine direction', 'a', 'Ezra 1:1 — "The LORD stirred up the spirit of Cyrus king of Persia." The author consistently attributes Persian royal decisions to divine initiative, reflecting a theology in which God directs world history to fulfil prophetic promises such as those in Jeremiah 25:11-12 and Isaiah 44:28.'),
('Ezra', 1, 'adults', 2, 'How does Cyrus''s decree in Ezra 1:2-4 compare to the prophecy in Isaiah 44:28, and what does this parallel signify?', 'Isaiah 44:28 names Cyrus by name and predicts he will say of Jerusalem "she shall be built" and of the temple "thy foundation shall be laid," which Ezra 1:2-3 records as literally fulfilled', 'Isaiah only predicted a Persian king would free the captives without naming Cyrus or mentioning the temple', 'The comparison is only thematic since Isaiah''s prophecy used different language from Cyrus''s actual decree', 'Isaiah predicted a decree by Darius, and Ezra reassigns the prophecy to Cyrus to harmonise the narratives', 'a', 'Isaiah 44:28 — "That saith of Cyrus, He is my shepherd, and shall perform all my pleasure: even saying to Jerusalem, Thou shalt be built; and to the temple, Thy foundation shall be laid." Ezra 1:2-3 records the fulfilment word for word, making this one of the most precisely verified Old Testament prophecies.'),
('Ezra', 1, 'adults', 3, 'What is the significance of Cyrus''s decree permitting a freewill offering for the house of God alongside practical support?', 'It distinguished between mandatory state support and voluntary personal giving, establishing that worship of the LORD was to be funded by willing hearts, not compulsion', 'It limited state expenditure by making the temple project entirely dependent on private donations', 'It shows Cyrus valued religious freedom but refused to commit Persian treasury funds to a foreign god', 'It was a requirement of Persian administrative law for all temple-building projects in the empire', 'a', 'Ezra 1:4 — "Beside the freewill offering for the house of God that is in Jerusalem." The distinction between compelled neighbourly support and freewill offering mirrors Israel''s own tabernacle funding (Exodus 35:5) where the foundation of worship was voluntary generosity.'),
('Ezra', 1, 'adults', 4, 'What does the inventory detail of temple vessels — broken down by category and totalling 5,400 in Ezra 1:9-11 — suggest about the author''s purpose?', 'It demonstrates the complete and faithful restoration of what was taken, establishing continuity between Solomon''s temple and the rebuilt one through material, not just spiritual, connection', 'It serves as a property receipt for the Persian administration to document the transfer of assets', 'It is primarily a literary device to show the wealth that returned with the exiles', 'It lists the vessels to allow later readers to identify any that were missing after the return', 'a', 'Ezra 1:9-11 — The detailed inventory culminates in "all the vessels of gold and of silver were five thousand and four hundred." This careful accounting shows that nothing Nebuchadnezzar took (2 Kings 25:13-16) was permanently lost; the restoration is total and verifiable.'),
('Ezra', 1, 'adults', 5, 'How does the exile-to-return narrative of Ezra 1 parallel the Exodus from Egypt, and what theological point does this make?', 'Both involve God stirring a pagan ruler to release his people, the people receiving silver and gold from their neighbours, and a journey back to the land of promise — presenting the return as a new Exodus', 'The parallel is only linguistic; the historical circumstances were too different for a genuine theological comparison', 'Ezra deliberately avoided Exodus imagery because the return was partial and the glory of the first temple was not replicated', 'The parallel is found only in Nehemiah, not in Ezra 1', 'a', 'Ezra 1:4 — neighbours giving "silver, and with gold, and with goods" echoes Exodus 3:21-22 where the Israelites plundered Egypt. God stirring Cyrus echoes God hardening then releasing Pharaoh. The author presents the return as a second Exodus, a new act of national redemption.'),
('Ezra', 1, 'adults', 6, 'What is the historical and canonical significance of identifying Sheshbazzar as "the prince of Judah" in Ezra 1:8?', 'It preserves the Davidic political identity of the returning community — a prince of Judah, not a Persian-appointed governor — establishing covenantal continuity with the pre-exilic kingdom', 'It was a Persian honorific title given to the leader of any returning ethnic group', 'Sheshbazzar''s Davidic lineage is confirmed in the genealogies of 1 Chronicles', 'It indicates Sheshbazzar was the chief priest rather than a civic leader', 'a', 'Ezra 1:8 — "Sheshbazzar, the prince of Judah." The Hebrew nasi (prince) was used for tribal leaders and Davidic figures. His identity as prince of Judah signals that the returned community retained covenantal identity under a Davidic representative, not merely as a Persian administrative unit.'),
('Ezra', 1, 'adults', 7, 'How does Ezra 1 position the whole book within the framework of biblical history from covenant promise to fulfilment?', 'It opens by citing Jeremiah''s prophecy as the controlling frame: the decree of Cyrus is not a political accident but the divinely timed end of the seventy years, placing all that follows under the rubric of promise-fulfilment', 'It opens with a regnal date to provide historical anchoring without theological comment', 'It begins with a genealogy to establish the legitimacy of the returning leaders', 'It opens with a prayer of Ezra himself recounting God''s faithfulness before narrating the historical events', 'a', 'Ezra 1:1 — "that the word of the LORD by the mouth of Jeremiah might be fulfilled." This opening clause is the theological thesis of the entire book: everything that follows — return, temple, opposition, dedication, Ezra''s mission, covenant renewal — is the outworking of God''s faithful word spoken through the prophets.'),
('Ezra', 1, 'adults', 8, 'What does the phrase "whose spirit God had raised" (Ezra 1:5) regarding those who rose to go up and build reveal about the nature of spiritual motivation in the restoration?', 'It shows that human willingness to obey God''s call is itself a divine gift — God who commanded the return also created the desire to return in those who obeyed', 'It implies that only those who felt a supernatural compulsion were permitted to join the return', 'It distinguishes the spiritually superior returnees from those who stayed behind in Babylon out of disobedience', 'It refers to prophetic visions given to the leaders that motivated the community to act', 'a', 'Ezra 1:5 — "Then rose up the chief of the fathers of Judah and Benjamin, and the priests, and the Levites, with all them whose spirit God had raised, to go up to build the house of the LORD which is in Jerusalem." The parallel with verse 1 (God stirring Cyrus) shows a consistent theology: both the pagan king and the covenant people are moved by God''s sovereign initiative.');

-- ═══ Ezra Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 2, 'kids', 1, 'Who led the first group of people back from Babylon to Jerusalem?', 'Zerubbabel and Jeshua', 'Ezra and Nehemiah', 'Moses and Aaron', 'Cyrus and Sheshbazzar', 'a', 'Ezra 2:2 — "Which came with Zerubbabel: Jeshua, Nehemiah, Seraiah, Reelaiah, Mordecai, Bilshan, Mizpar, Bigvai, Rehum, Baanah."'),
('Ezra', 2, 'kids', 2, 'What was the total number of people who returned from captivity to Jerusalem?', 'Forty and two thousand three hundred and threescore', 'Twenty thousand and five hundred', 'Sixty thousand and four', 'Thirty thousand and two hundred', 'a', 'Ezra 2:64 — "The whole congregation together was forty and two thousand three hundred and threescore."'),
('Ezra', 2, 'kids', 3, 'What did the leaders give as a gift when they arrived at the house of the LORD in Jerusalem?', 'Gold and silver and priests'' garments for the work of God', 'Lambs and doves for sacrifice', 'Fine flour and oil for the priests', 'Cedar wood from Lebanon for building', 'a', 'Ezra 2:69 — "They gave after their ability unto the treasure of the work threescore and one thousand drams of gold, and five thousand pound of silver, and one hundred priests'' garments."'),
-- Teens
('Ezra', 2, 'teens', 1, 'What problem did certain families face because they could not prove their lineage when they returned from Babylon?', 'They could not prove they were of Israel and were treated as polluted and excluded from the priesthood', 'They were sent back to Babylon until proper records could be found', 'They were required to pay a tax to the Persian governor before being allowed to settle', 'They were only permitted to live outside Jerusalem until the temple was completed', 'a', 'Ezra 2:62 — "These sought their register among those that were reckoned by genealogy, but they were not found: therefore were they, as polluted, put from the priesthood."'),
('Ezra', 2, 'teens', 2, 'What did the governor tell the priests who could not prove their genealogy to wait for before eating of the most holy things?', 'A priest with Urim and Thummim who could determine the matter', 'The completion of the temple so God could reveal the answer', 'The return of Ezra who would judge such cases', 'The decree of the Persian king settling questions of priestly identity', 'a', 'Ezra 2:63 — "The Tirshatha said unto them, that they should not eat of the most holy things, till there stood up a priest with Urim and with Thummim."'),
('Ezra', 2, 'teens', 3, 'In addition to the 42,360 people, how many servants and singing men and women returned?', 'Seven thousand three hundred thirty and seven servants and two hundred singing men and singing women', 'Five thousand servants and one hundred singing men and women', 'Ten thousand servants and three hundred musicians', 'Three thousand servants and fifty singers', 'a', 'Ezra 2:65 — "Beside their servants and their maids, of whom there were seven thousand three hundred thirty and seven: and there were among them two hundred singing men and singing women."'),
('Ezra', 2, 'teens', 4, 'What animals did the returning exiles bring with them according to Ezra 2:66-67?', 'Seven hundred thirty and six horses, two hundred forty and five mules, four hundred thirty and five camels, and six thousand seven hundred and twenty asses', 'One thousand horses, five hundred mules, three hundred camels, and two thousand asses', 'Five hundred horses, one hundred mules, two hundred camels, and one thousand asses', 'Three hundred horses, fifty mules, one hundred camels, and five hundred asses', 'a', 'Ezra 2:66-67 — "Their horses were seven hundred thirty and six; their mules, two hundred forty and five; Their camels, four hundred thirty and five; their asses, six thousand seven hundred and twenty."'),
('Ezra', 2, 'teens', 5, 'Where did the people of Israel, priests, Levites, and others dwell when they arrived in their cities?', 'Every one in his own city', 'All together in Jerusalem until the temple was built', 'In tents outside Jerusalem until houses could be constructed', 'In the cities of Judah and Benjamin only', 'a', 'Ezra 2:70 — "So the priests, and the Levites, and some of the people, and the singers, and the porters, and the Nethinims, dwelt in their cities, and all Israel in their cities."'),
-- Adults
('Ezra', 2, 'adults', 1, 'What is the literary and theological purpose of the long genealogical list in Ezra 2, which is repeated almost verbatim in Nehemiah 7?', 'It establishes the legitimacy of the restored community by demonstrating verifiable continuity with pre-exilic Israel, making the return a restoration of a defined covenant people, not a new beginning', 'It was included purely for administrative record-keeping with no theological function', 'It was intended to provide legal property titles to the returnees based on their ancestral towns', 'It was inserted by a later editor to harmonise Ezra with Nehemiah', 'a', 'Ezra 2:1 — "These are the children of the province that went up out of the captivity." The list functions as a charter document: the returned community is not a new nation but the same covenant people whose identity is traceable, whose priests are verifiable, and whose towns are ancestral.'),
('Ezra', 2, 'adults', 2, 'What is the significance of the specific mention of families who could not prove their Israelite ancestry (Ezra 2:59-60) alongside those who could not prove priestly descent (Ezra 2:61-62)?', 'It shows the community took genealogical integrity seriously for two different reasons — covenantal membership for laypeople and ritual purity for priests — and that uncertainty was handled by suspension rather than exclusion', 'It shows the community was indifferent to genealogical claims and accepted all who claimed to be Israelites', 'It was a Persian administrative requirement to verify the ethnicity of all returnees before granting land rights', 'It shows only priestly genealogy mattered; lay Israelites with uncertain ancestry were fully integrated', 'a', 'Ezra 2:62-63 — Those of the priestly line who could not find their register "were put from the priesthood...till there stood up a priest with Urim and Thummim." The dual concern for lay and priestly identity shows a community committed to integrity in worship and covenant membership.'),
('Ezra', 2, 'adults', 3, 'What does the mention of Urim and Thummim in Ezra 2:63 reveal about the post-exilic community''s understanding of its own incompleteness?', 'It reveals that the community knew certain questions of divine revelation could not be answered without the full restoration of the high-priestly oracular instrument, which had been absent since before the exile', 'It shows the community expected the Urim and Thummim to be found among the temple vessels returned by Cyrus', 'It indicates the governor believed the Urim and Thummim were still in use and accessible', 'It reveals a disagreement between the governor and the priests about who had authority to rule on genealogical questions', 'a', 'Ezra 2:63 — "Till there stood up a priest with Urim and with Thummim." The Urim and Thummim had not functioned since the monarchy period; their invocation here acknowledges that the post-exilic restoration was real but incomplete — full divine guidance awaited a future fuller restoration.'),
('Ezra', 2, 'adults', 4, 'How does the freewill giving at the house of God in Ezra 2:68-69 echo the construction of the tabernacle in Exodus, and what is the theological continuity this establishes?', 'Both the tabernacle (Exodus 35:21-29) and the temple restoration were funded by freewill offerings from the people according to their ability, showing that authentic worship has always been sustained by willing-heart generosity, not compulsion', 'The Exodus tabernacle was funded by a temple tax while Ezra''s temple relied only on royal grants', 'The comparison shows the returned community was wealthier than the wilderness generation', 'The freewill offering in Ezra 2 was a Persian legal requirement for conquered peoples, not a spiritual act', 'a', 'Ezra 2:68-69 — "Some of the chief of the fathers...offered freely for the house of God...They gave after their ability." Exodus 35:21 — "every one whose heart stirred him up, and every one whom his spirit made willing...they brought the LORD''s offering." The same Spirit-motivated generosity undergirds both acts of worship.'),
('Ezra', 2, 'adults', 5, 'What is the significance of the number 42,360 in Ezra 2:64 matching Nehemiah 7:66 despite internal subtotals in both lists not adding up to that figure?', 'It suggests both lists draw from a common official register; the discrepancy in subtotals likely reflects different counting categories (e.g., including or excluding women, or groups counted elsewhere), but the total represents the authoritative census figure', 'It is a scribal error in one of the books that has never been satisfactorily resolved', 'The number 42,360 was a symbolic round number used in ancient Near Eastern documents without precise meaning', 'It proves the two lists are from different returns and should not be harmonised', 'a', 'Ezra 2:64 — "The whole congregation together was forty and two thousand three hundred and threescore." Nehemiah 7:66 gives the same total. Scholars note the subtotals in each list differ and reach only about 30,000; the additional names were likely in categories not enumerated in the preserved lists.'),
('Ezra', 2, 'adults', 6, 'What does the presence of "singing men and singing women" (Ezra 2:65) in the returning community reveal about the priority of worship in the restoration?', 'It shows that liturgical song was considered essential enough to the restored community that professional singers were counted among the returning exiles, not merely practical workers', 'It reflects Persian cultural custom of travelling with musicians for entertainment on long journeys', 'It shows the singers were slaves of the wealthy families rather than dedicated worship ministers', 'It indicates the temple was expected to be completed immediately upon arrival, requiring singers from day one', 'a', 'Ezra 2:65 — "There were among them two hundred singing men and singing women." The inclusion of singers alongside priests, Levites, and porters in the official register signals that the community viewed worship — including its musical dimension — as foundational to the restoration, not incidental.'),
('Ezra', 2, 'adults', 7, 'How does the structure of Ezra 2 — moving from leaders (v.2) through lay families (vv.3-35), villages (vv.21-35), priests (vv.36-39), Levites (vv.40-42), temple servants (vv.43-58), and uncertain lineage (vv.59-63) — reflect a theology of ordered community?', 'It mirrors the structure of Israel''s pre-exilic society with its distinct classes of leadership, worship, and service — showing the restoration reconstitutes the full social and religious order, not just a remnant', 'It follows Persian administrative protocol for documenting returning subject peoples', 'It emphasises the priests above all other groups, reflecting post-exilic theocratic priorities', 'It is an organisational convenience with no theological meaning', 'a', 'Ezra 2:2-63 — The ordered progression through every class of Israelite society shows the return is a comprehensive restoration: every role from civil leader to temple doorkeeper is represented, reconstituting the full body of the covenant community.'),
('Ezra', 2, 'adults', 8, 'What does the detail that the returnees settled "every one in his own city" (Ezra 2:70) fulfil in terms of prophetic promise?', 'It fulfils the promise of land restoration central to the covenant — God''s people returning to their ancestral inheritances is the concrete sign that the curse of exile is being reversed', 'It was a practical Persian administrative decision to prevent overcrowding in Jerusalem', 'It shows the people preferred their old towns over Jerusalem and ignored the call to rebuild the city', 'It fulfils only the logistical need to distribute the large returning population across available settlements', 'a', 'Ezra 2:70 — "All Israel in their cities." The resettlement of ancestral towns fulfils Deuteronomy 30:3-5 — "the LORD thy God will...gather thee from all the nations...and will bring thee into the land which thy fathers possessed." Settling in their cities is the physical embodiment of the promised restoration of inheritance.');

-- ═══ Ezra Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 3, 'kids', 1, 'What was the first thing the people built when they returned to Jerusalem?', 'The altar of God to offer burnt offerings on it', 'The wall around the city', 'The king''s house in Jerusalem', 'A market in the centre of the city', 'a', 'Ezra 3:2 — "Then stood up Jeshua the son of Jozadak, and his brethren the priests, and Zerubbabel the son of Shealtiel, and his brethren, and builded the altar of the God of Israel, to offer burnt offerings thereon."'),
('Ezra', 3, 'kids', 2, 'When the builders laid the foundation of the temple, what did some of the older people do?', 'They wept with a loud voice', 'They sang and danced in the streets', 'They went back to their homes in sadness', 'They prayed in silence for three days', 'a', 'Ezra 3:12 — "Many of the priests and Levites and chief of the fathers, who were ancient men, that had seen the first house, when the foundation of this house was laid before their eyes, wept with a loud voice."'),
('Ezra', 3, 'kids', 3, 'What did the priests and Levites do when the foundation of the temple was laid?', 'They praised the LORD with cymbals and trumpets, singing that he is good and his mercy endureth for ever', 'They offered one hundred bulls as a burnt offering', 'They read from the law of Moses to the people', 'They blew the shofar and marched around the site seven times', 'a', 'Ezra 3:10-11 — "They set the priests in their apparel with trumpets, and the Levites the sons of Asaph with cymbals, to praise the LORD...singing praise and giving thanks unto the LORD; because he is good, for his mercy endureth for ever toward Israel."'),
-- Teens
('Ezra', 3, 'teens', 1, 'Why did the people rebuild the altar even though they were afraid of the people of those lands around them?', 'Fear was upon them because of the people of those countries, yet they offered burnt offerings upon the altar unto the LORD', 'They had the protection of the Persian army so they felt safe to build', 'The altar was already standing and only needed minor repair', 'They built the altar secretly at night so the surrounding peoples would not notice', 'a', 'Ezra 3:3 — "They set the altar upon his bases; for fear was upon them because of the people of those countries: and they offered burnt offerings thereon unto the LORD, even burnt offerings morning and evening."'),
('Ezra', 3, 'teens', 2, 'During what feast did the people first offer burnt offerings after returning, and when did regular offerings resume?', 'They kept the feast of tabernacles and offered daily burnt offerings from the first day of the seventh month', 'They kept the Passover on the fourteenth day and then offered sacrifices weekly', 'They celebrated the feast of weeks and offered firstfruits on the fiftieth day', 'They offered sacrifices at the new moon of the first month and resumed daily offerings the next year', 'a', 'Ezra 3:4-6 — "They kept also the feast of tabernacles...From the first day of the seventh month began they to offer burnt offerings unto the LORD."'),
('Ezra', 3, 'teens', 3, 'What materials did the people of Sidon and Tyre bring by sea to help build the temple?', 'Cedar trees from Lebanon to the port of Joppa', 'Stones of marble from the quarries of Tyre', 'Gold and silver brought by ships from Tarshish', 'Timber from the forests of Lebanon loaded on camels', 'a', 'Ezra 3:7 — "They gave money also unto the masons, and to the carpenters; and meat, and drink, and oil, unto them of Zidon, and to them of Tyre, to bring cedar trees from Lebanon to the sea of Joppa."'),
('Ezra', 3, 'teens', 4, 'In what year of their coming to Jerusalem did the Levites twenty years old and upward begin to oversee the work of the temple?', 'The second year, in the second month', 'The first year, in the seventh month', 'The third year, after the altar was dedicated', 'The fourth year, when Cyrus renewed his decree', 'a', 'Ezra 3:8 — "Now in the second year of their coming unto the house of God at Jerusalem, in the second month, began Zerubbabel...and appointed the Levites, from twenty years old and upward, to set forward the work of the house of the LORD."'),
('Ezra', 3, 'teens', 5, 'How did the sound of weeping and rejoicing at the temple foundation laying appear to those far away?', 'The people could not discern the noise of the shout of joy from the noise of the weeping', 'The weeping was louder and was heard as far as Jericho', 'The rejoicing drowned out the weeping and was heard in all the land', 'The two sounds were heard on different days so both carried clearly across the land', 'a', 'Ezra 3:13 — "The people could not discern the noise of the shout of joy from the noise of the weeping of the people: for the people shouted with a loud shout, and the noise was heard afar off."'),
-- Adults
('Ezra', 3, 'adults', 1, 'What is the theological significance of rebuilding the altar before laying the temple foundation in Ezra 3:2-3?', 'It establishes that restored worship — the daily offering — takes precedence over the building program; the people reestablish their relationship with God through sacrifice before constructing the physical sanctuary', 'It was a practical necessity since offerings were needed to fund the building project', 'It reflects the Mosaic law requiring an altar at every place where God''s name was recorded', 'It shows the priests had more authority than the civil leaders like Zerubbabel', 'a', 'Ezra 3:2-3 — The altar is built and offerings resumed before a single stone of the temple is laid. This sequence mirrors Israel''s wilderness priority: the altar (Exodus 20:24) preceded the tabernacle. Restoring the sacrificial system was the first act of covenant renewal, not a secondary concern.'),
('Ezra', 3, 'adults', 2, 'How does the reference to Jeshua and Zerubbabel in Ezra 3 fulfil the dual leadership model prophesied in Zechariah''s vision of the two olive trees?', 'Both Haggai and Zechariah identify Zerubbabel (civil leader, Davidic line) and Jeshua (high priest) as the two anointed ones through whom the temple would be completed, representing the dual priestly-royal restoration', 'Zechariah''s olive tree vision referred to Moses and Aaron, not to post-exilic leaders', 'The dual leadership model in Ezra was a Persian administrative arrangement with no prophetic significance', 'Zerubbabel was the high priest and Jeshua the governor in the post-exilic period', 'a', 'Ezra 3:2 — "Jeshua...and Zerubbabel." Zechariah 4:14 — "These are the two anointed ones, that stand by the LORD of the whole earth." Zechariah 6:13 — "the counsel of peace shall be between them both." The two leaders of Ezra 3 are the fulfilment of the prophetic vision of priestly-royal cooperation in restoration.'),
('Ezra', 3, 'adults', 3, 'What is the significance of the people offering burnt offerings "morning and evening" (Ezra 3:3) in the context of the exile?', 'It signals the restoration of the tamid (daily continual offering) commanded in Exodus 29:38-42, which had been interrupted by the destruction of the temple — its resumption marks the re-establishment of the covenant relationship', 'It simply reflects the twice-daily custom of the Babylonian temples the exiles had observed', 'It was required by Cyrus''s decree as a condition of the return', 'It shows the people were more devout than their pre-exilic ancestors who had neglected the morning offering', 'a', 'Ezra 3:3 — "they offered burnt offerings thereon...even burnt offerings morning and evening." Exodus 29:38-42 commanded the two daily lambs as the perpetual covenant sign. The first act of restored worship was to restart this fundamental rhythm of Israel''s relationship with God.'),
('Ezra', 3, 'adults', 4, 'What does the mixed response of weeping and shouting in Ezra 3:12-13 reveal about the nature of the restoration?', 'It shows the restoration was real but incomplete — older men wept because the new temple''s foundation was visibly smaller and less glorious than Solomon''s, while the younger generation rejoiced at what was beginning, both responses being theologically valid', 'The weeping was sinful unbelief and the rejoicing was proper faith; Haggai rebuked the weepers', 'The weeping was entirely joyful, not sorrowful — tears of overwhelming happiness at the fulfilment of God''s promise', 'The older men were weeping because they opposed the rebuilding and the younger men were forcing it through', 'a', 'Ezra 3:12-13 — "Many of the priests...ancient men, that had seen the first house...wept with a loud voice; and many shouted aloud for joy." Haggai 2:3 — "Who is left among you that saw this house in her first glory? and how do ye see it now?" The tension between memory of glory and present reality is real and canonical.'),
('Ezra', 3, 'adults', 5, 'How does the praise refrain in Ezra 3:11 — "He is good, for his mercy endureth for ever toward Israel" — function as a theological statement in the context of the return from exile?', 'It is Israel''s fundamental doxology (from Psalms 106, 107, 118, 136) now applied to the return from exile, declaring that God''s hesed (covenant faithfulness) has survived the judgment of captivity and is active in restoration', 'It was a new song composed specifically for the dedication of the temple foundation', 'It was a Persian royal formula adapted for Israelite use in the restored community', 'It was sung only by the Levites as a liturgical duty with no specific theological significance in context', 'a', 'Ezra 3:11 — "singing praise and giving thanks unto the LORD; because he is good, for his mercy endureth for ever toward Israel." This refrain appears verbatim in Psalms 106:1, 107:1, 118:1, and throughout Psalm 136. Its use here declares that the promises undergirding those psalms are being fulfilled in the restoration.'),
('Ezra', 3, 'adults', 6, 'What is the connection between the cedar procurement from Lebanon and Tyre in Ezra 3:7 and the building of Solomon''s temple in 1 Kings 5?', 'Both projects used cedar from Lebanon transported through Joppa with Phoenician assistance — the restored community deliberately replicated Solomon''s procurement method to establish continuity with the first temple', 'The cedar procurement in Ezra was entirely different from Solomon''s, using overland routes rather than sea transport', 'The Tyrians and Sidonians demanded payment in gold from the exiles whereas they had given cedar freely to Solomon', 'The connection is coincidental since Lebanon cedar was the only available timber for construction projects in the region', 'a', 'Ezra 3:7 — "cedar trees from Lebanon to the sea of Joppa." 1 Kings 5:8-9 — "I will convey them by sea in floats unto the place that thou shalt appoint me...they shall come unto thee." The identical logistics signal a deliberate typological connection: the second temple inherits the architectural and covenantal identity of the first.'),
('Ezra', 3, 'adults', 7, 'What does the authorization framework in Ezra 3:7 — "according to the grant that they had of Cyrus king of Persia" — reveal about how the post-exilic community understood divine and human authority?', 'It shows the community worked within legitimate imperial structures while understanding that the real grant came from God — Cyrus''s decree was the human vehicle of divine permission', 'It shows the community was entirely dependent on Persian political authority for its religious life', 'It shows the community was subversive toward Persia and cited Cyrus only as legal cover for their actual religious motivations', 'It reveals tension between the priestly leadership who wanted divine authority only and the civil leaders who relied on Persian approval', 'a', 'Ezra 3:7 — "according to the grant that they had of Cyrus king of Persia." The community operated transparently within Persian law while Ezra 1:1 established that Cyrus''s grant was itself God''s doing. The two authorities are complementary, not competing — a pattern continued throughout Ezra-Nehemiah.'),
('Ezra', 3, 'adults', 8, 'How does Ezra 3''s account of the altar rebuilding and foundation laying set up the theological crisis that dominates chapters 4-6?', 'The public celebration of the foundation (Ezra 3:10-13) is immediately followed in chapter 4 by adversarial opposition, showing that every genuine act of covenant restoration will face resistance — the glory of the foundation and the suffering of the opposition are two sides of the same story', 'Chapter 4 is an administrative digression with no connection to the worship events of chapter 3', 'The opposition in chapter 4 was triggered by the weeping of the old men which the enemies interpreted as dissatisfaction with Persian rule', 'Ezra 3 and 4 are from different historical sources and should not be read as a continuous narrative', 'a', 'Ezra 3:10-13 describes the joyful foundation celebration; Ezra 4:1 immediately opens with "Now when the adversaries of Judah and Benjamin heard that the children of the captivity builded the temple." The narrative structure makes the opposition a direct response to the restoration, establishing the theological pattern of Ezra-Nehemiah: faithful rebuilding provokes hostile resistance.');

-- ═══ Ezra Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 4, 'kids', 1, 'What did the enemies of Judah and Benjamin ask Zerubbabel and the leaders when they heard the temple was being built?', 'Let us build with you, for we seek your God as ye do', 'Why are you building without the king''s permission?', 'Give us a share of the land and we will stop our opposition', 'Tell us the name of your God so we may worship him too', 'a', 'Ezra 4:2 — "They came to Zerubbabel, and to the chief of the fathers, and said unto them, Let us build with you: for we seek your God, as ye do."'),
('Ezra', 4, 'kids', 2, 'What did Zerubbabel and the leaders say to the enemies who wanted to help build the temple?', 'Ye have nothing to do with us to build an house unto our God', 'You may help if the Persian king gives permission', 'We will allow you to provide materials but not to lay the stones', 'Come and work alongside us if you truly worship the LORD', 'a', 'Ezra 4:3 — "But Zerubbabel, and Jeshua, and the rest of the chief of the fathers of Israel, said unto them, Ye have nothing to do with us to build an house unto our God."'),
('Ezra', 4, 'kids', 3, 'What happened to the work on the temple after the adversaries sent a letter to the king?', 'The work was made to cease and stopped until the second year of Darius', 'The workers were arrested and taken back to Babylon', 'The king sent soldiers to tear down what had been built', 'The people kept building in secret at night', 'a', 'Ezra 4:24 — "Then ceased the work of the house of God which is at Jerusalem. So it ceased unto the second year of the reign of Darius king of Persia."'),
-- Teens
('Ezra', 4, 'teens', 1, 'How did the adversaries try to discourage the people of Judah when they could not join the building project?', 'They weakened the hands of the people of Judah and troubled them in building and hired counsellors against them', 'They spread false reports that Cyrus had died and his decree was void', 'They bribed the Persian treasury officials to withhold building funds', 'They gathered an army and threatened to attack Jerusalem if building continued', 'a', 'Ezra 4:4-5 — "Then the people of the land weakened the hands of the people of Judah, and troubled them in building, and hired counsellors against them, to frustrate their purpose."'),
('Ezra', 4, 'teens', 2, 'To which king did the adversaries write their accusatory letter after Cyrus, saying Jerusalem was a rebellious city?', 'Artaxerxes', 'Darius', 'Xerxes', 'Cambyses', 'a', 'Ezra 4:7 — "And in the days of Artaxerxes wrote Bishlam, Mithredath, Tabeel, and the rest of their companions, unto Artaxerxes king of Persia." The main letter in Ezra 4:11-16 is addressed to Artaxerxes.'),
('Ezra', 4, 'teens', 3, 'What did the letter to Artaxerxes warn would happen if Jerusalem were rebuilt?', 'They will not pay toll, tribute, and custom, and the king''s revenue will be diminished, and that the city was rebellious and would cause him to have no portion on this side of the river', 'The Israelites would raise an army and attack Persia from the west', 'The temple would become a military fortress threatening all the eastern provinces', 'The Jews would seek to form alliances with Egypt and Babylon against Persia', 'a', 'Ezra 4:13,16 — "If this city be builded...they will not pay toll, tribute, and custom...we certify the king that, if this city be builded again...then shalt thou have no portion on this side the river."'),
('Ezra', 4, 'teens', 4, 'What did Artaxerxes command after reading the letter from the adversaries?', 'Give ye now commandment to cause these men to cease, and that this city be not builded', 'Send an army to investigate whether Jerusalem was truly being rebuilt', 'Let the governor of the province review the original decree of Cyrus', 'Give the adversaries permission to live in Jerusalem alongside the Jews', 'a', 'Ezra 4:21 — "Give ye now commandment to cause these men to cease, and that this city be not builded, until another commandment shall be given from me."'),
('Ezra', 4, 'teens', 5, 'Who were the two men named as writers of the accusatory letter to Artaxerxes mentioned in Ezra 4:8?', 'Rehum the chancellor and Shimshai the scribe', 'Bishlam and Mithredath', 'Tattenai and Shetharboznai', 'Sanballat and Tobiah', 'a', 'Ezra 4:8 — "Rehum the chancellor and Shimshai the scribe wrote a letter against Jerusalem to Artaxerxes the king."'),
-- Adults
('Ezra', 4, 'adults', 1, 'What was the true motive behind the adversaries'' offer to help build the temple in Ezra 4:2, and how does Zerubbabel''s refusal reflect sound theological principle?', 'The adversaries sought to infiltrate and corrupt the restored community by mixing worship; Zerubbabel''s refusal preserved the integrity of the covenant community''s worship as exclusively Yahweh-centred', 'The adversaries genuinely wanted to worship God and Zerubbabel''s refusal was unnecessarily exclusive', 'The adversaries were Persian officials enforcing oversight of the building project', 'Zerubbabel refused because of a racial prejudice against the mixed peoples of the land', 'a', 'Ezra 4:2-3 — Their claim "we seek your God, as ye do" was undermined by their identity as peoples resettled by Assyria who "feared the LORD, and served their own gods" (2 Kings 17:33). Zerubbabel''s refusal was not racial but theological: syncretistic participation would compromise the temple''s witness as a house of the LORD alone.'),
('Ezra', 4, 'adults', 2, 'Ezra 4:6-23 appears to be a parenthetical account of later opposition under Xerxes and Artaxerxes interrupting the Darius narrative. What literary purpose does this digression serve?', 'It demonstrates the persistent pattern of opposition across multiple reigns, showing that resistance to the restoration was not a single incident but an ongoing spiritual conflict that required ongoing faithfulness', 'It is a scribal error that merged two different historical accounts', 'It shows that the opposition under Darius was successful and permanently stopped the project', 'It is evidence that Ezra composed the book after Nehemiah and inserted the later material out of chronological order accidentally', 'a', 'Ezra 4:6-23 jumps from Cyrus-era opposition (vv.1-5) to Xerxes and Artaxerxes (vv.6-23) before returning to Darius in v.24. This is a thematic arrangement: the author groups all opposition letters together to establish the motif of persistent resistance before narrating the triumph of completion in chapters 5-6.'),
('Ezra', 4, 'adults', 3, 'What is the significance of the adversaries'' citation of history in their letter — "this city hath been in old time moved sedition against kings" — as a rhetorical strategy in Ezra 4:15,19?', 'They weaponised the genuine history of Israel''s monarchical resistance to Assyria and Babylon to cast the restoration in the worst possible light for a Persian king anxious about western rebellions', 'The accusation was entirely fabricated and had no basis in Israel''s actual history', 'They were referring specifically to Hezekiah''s alliance with Egypt against Assyria, which was well known in Persian records', 'Their historical argument was weak and Artaxerxes initially dismissed it before being pressured by his advisors', 'a', 'Ezra 4:15,19 — "a search may be made in the book of the records...this city hath been in old time moved sedition against kings." The search would find records of Israel''s and Judah''s resistance to Assyrian and Babylonian domination — historically accurate facts used with selective, malicious intent.'),
('Ezra', 4, 'adults', 4, 'What does the command "give ye now commandment to cause these men to cease...until another commandment shall be given from me" (Ezra 4:21) inadvertently reveal about how God was overruling even Persian opposition?', 'Artaxerxes left open the door for a future reversal ("until another commandment") which Ezra 7 and Nehemiah 2 show was indeed given — even the stop-work order contained the seed of its own reversal', 'The command was absolute and permanent, showing Persian power was superior to God''s purposes temporarily', 'The phrase "until another commandment" was standard Persian legal formulary with no significance for the narrative', 'It shows Artaxerxes was secretly sympathetic to the Jews and deliberately left the reversal clause for their benefit', 'a', 'Ezra 4:21 — "until another commandment shall be given from me." In Ezra 7:13 and Nehemiah 2:7-8 Artaxerxes himself issues the "another commandment," granting both Ezra and Nehemiah permission to proceed. The king''s own stop-work order contained its own expiry clause, demonstrating God''s sovereign orchestration even through hostile decrees.'),
('Ezra', 4, 'adults', 5, 'How does the hiring of "counsellors against them to frustrate their purpose" (Ezra 4:5) reflect the tactics of spiritual opposition described in broader biblical narrative?', 'It mirrors the pattern of using legitimate legal and political channels to oppose God''s work — the enemy operates within the system rather than through direct violence, a pattern seen from Laban opposing Jacob to the Pharisees opposing Jesus', 'It shows the opposition was purely political with no spiritual dimension', 'It indicates the adversaries had greater legal resources than the returned community and could legitimately block the project', 'It shows that the Persian administrative system was fundamentally corrupt and easily manipulated against minority communities', 'a', 'Ezra 4:5 — "hired counsellors against them, to frustrate their purpose, all the days of Cyrus king of Persia, even until the reign of Darius king of Persia." The sustained, legally-framed opposition shows a deliberate strategy to exploit imperial bureaucracy against the covenant community, a pattern that recurs in Nehemiah, Esther, and Daniel.'),
('Ezra', 4, 'adults', 6, 'What is the theological irony in the adversaries'' letter claiming the Jews would "have no portion on this side the river" (Ezra 4:16) if Jerusalem is rebuilt?', 'They intended to threaten the king with financial loss but unwittingly used language resonant with the Abrahamic land covenant — "portion" and "river" (Euphrates) are boundary terms in Genesis 15:18 — thus framing the restoration in covenantal geography', 'The threat was purely financial and administrative with no biblical resonance', 'The term "this side the river" refers to the Euphrates as a Persian administrative boundary with no covenantal significance', 'The irony is that the adversaries were the ones with no real portion in the land according to Ezra 4:3', 'a', 'Ezra 4:16 — "thou shalt have no portion on this side the river." Genesis 15:18 — "the LORD made a covenant with Abram, saying, Unto thy seed have I given this land, from the river of Egypt unto the great river, the river Euphrates." The adversaries'' threat inadvertently described the very land God had promised Israel.'),
('Ezra', 4, 'adults', 7, 'How does the cessation of the temple work "unto the second year of Darius" (Ezra 4:24) connect to the ministry of Haggai and Zechariah in Ezra 5:1?', 'The cessation created the historical context for Haggai and Zechariah''s prophetic ministry — their call to "build the house" (Haggai 1:8) was precisely the divine response to the paralysis of Ezra 4, showing prophetic word as the engine restarting stalled obedience', 'The connection is chronological only; the prophets were addressing different concerns than the temple stoppage', 'Haggai and Zechariah ministered before the stoppage and were the cause of the resumed building, not a response to its cessation', 'The gap between cessation and the second year of Darius was only a few months and needed no prophetic intervention', 'a', 'Ezra 4:24 — work ceased "unto the second year of Darius." Ezra 5:1-2 — "Then the prophets, Haggai the prophet, and Zechariah...prophesied unto the Jews...then rose up Zerubbabel...and began to build." Haggai 1:2-4 explicitly rebukes the people for saying "The time is not come...to build the LORD''s house" — the prophets addressed the theological capitulation behind the administrative stoppage.'),
('Ezra', 4, 'adults', 8, 'What does Ezra 4 as a whole reveal about the relationship between faithfulness, opposition, and the sovereignty of God in the restoration narrative?', 'It shows that genuine covenant faithfulness (Zerubbabel''s refusal to compromise, Ezra 4:3) provokes real and sustained opposition, but that God''s purposes are not ultimately frustrated — the same Persian imperial system used to stop the work will later be used to restart it', 'It shows that accommodation of opponents (accepting their help) would have prevented the opposition and been the wiser course', 'It reveals that the restoration was largely a human achievement with God''s involvement limited to inspiring the initial decree of Cyrus', 'It demonstrates that political opposition always defeats genuine religious renewal and the temple was only completed by diplomatic compromise', 'a', 'Ezra 4:3-24 narrates sustained opposition, yet Ezra 6:14-15 records the temple''s completion "according to the commandment of the God of Israel, and according to the commandment of Cyrus, and Darius, and Artaxerxes." Every hostile element in chapter 4 is overruled by chapter 6 — the opposition becomes the backdrop against which God''s faithfulness is displayed.');

-- ═══ Ezra Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 5, 'kids', 1, 'Which two prophets encouraged the Jews to start building the temple again?', 'Haggai and Zechariah the son of Iddo', 'Isaiah and Jeremiah', 'Elijah and Elisha', 'Daniel and Ezekiel', 'a', 'Ezra 5:1 — "Then the prophets, Haggai the prophet, and Zechariah the son of Iddo, prophesied unto the Jews that were in Judah and Jerusalem in the name of the God of Israel."'),
('Ezra', 5, 'kids', 2, 'Who was the governor on the other side of the river who came to ask the Jews who gave them permission to build?', 'Tattenai, governor beyond the river', 'Rehum the chancellor', 'Artaxerxes the king''s servant', 'Sanballat the Horonite', 'a', 'Ezra 5:3 — "At the same time came to them Tatnai, governor on this side the river, and Shetharboznai, and their companions, and said thus unto them, Who hath commanded you to build this house?"'),
('Ezra', 5, 'kids', 3, 'Did the officials stop the Jews from building while they waited for the king''s answer?', 'No, God was watching over the elders and they did not stop them until the matter came to Darius', 'Yes, all building stopped until a royal decree was received', 'Yes, the workers were arrested and kept in custody', 'No, because the Jews paid a large fine to keep building', 'a', 'Ezra 5:5 — "But the eye of their God was upon the elders of the Jews, that they could not cause them to cease, till the matter came to Darius: and then they returned answer by letter concerning this matter."'),
-- Teens
('Ezra', 5, 'teens', 1, 'What was the response of the Jewish leaders when Tattenai asked for the names of the men building the temple?', 'They gave him a list of the names of the men that were the chief of them and told him Cyrus had given the decree', 'They refused to answer and sent him away', 'They told him to ask the high priest who kept all official records', 'They said their names were written in the book of life and no earthly governor could demand them', 'a', 'Ezra 5:4,10 — "Then said we unto them after this manner, What are the names of the men that make this building?...we asked their names also, to certify thee, that we might write the names of the men that were the chief of them."'),
('Ezra', 5, 'teens', 2, 'In the letter Tattenai sent to Darius, what did the Jewish elders say about who had given them authority to build?', 'We are the servants of the God of heaven and earth, and build the house that was builded these many years ago, which a great king of Israel builded and set up', 'We build under the authority of Sheshbazzar the prince of Judah who has Cyrus''s original decree', 'Our authority comes from the prophets Haggai and Zechariah whom God sent to command us', 'We build by the authority of the elders of Babylon who confirmed our right to return', 'a', 'Ezra 5:11 — "And thus they returned us answer, saying, We are the servants of the God of heaven and earth, and build the house that was builded these many years ago, which a great king of Israel builded and set up."'),
('Ezra', 5, 'teens', 3, 'What did the Jewish elders tell Tattenai was the reason Jerusalem and the temple had been destroyed?', 'Because their fathers provoked the God of heaven unto wrath, he gave them into the hand of Nebuchadnezzar who destroyed the temple', 'Because the Babylonians were stronger and God had not yet given them victory', 'Because the priests had failed to maintain the daily offerings for many years', 'Because the king of Assyria had carried away the best craftsmen who could defend the city', 'a', 'Ezra 5:12 — "But after that our fathers had provoked the God of heaven unto wrath, he gave them into the hand of Nebuchadnezzar the king of Babylon, the Chaldean, who destroyed this house."'),
('Ezra', 5, 'teens', 4, 'What did the Jewish elders say had happened to Sheshbazzar when Cyrus commanded the temple to be built?', 'Cyrus put the vessels in his hand and commanded him to go to Jerusalem and let the house of God be builded in his place', 'He was given a Persian army to escort him safely back to Jerusalem', 'He was appointed high priest of Jerusalem by Cyrus and given a salary from the treasury', 'He received the vessels and gave them to Zerubbabel who led the actual return', 'a', 'Ezra 5:14-15 — "And the vessels also of gold and silver of the house of God...those did Cyrus the king take out of the temple of Babylon, and they were delivered unto one, whose name was Sheshbazzar...And said unto him, Take these vessels, go, carry them into the temple that is in Jerusalem."'),
('Ezra', 5, 'teens', 5, 'What did Tattenai ask Darius to do regarding the accusation against the Jews building the temple?', 'Let a search be made in the king''s treasure house at Babylon to find the decree of Cyrus', 'Send a commander to arrest Zerubbabel and bring him to Persia for judgment', 'Issue a new decree either confirming or withdrawing permission to build the temple', 'Commission a group of Persian priests to verify whether the God of Israel was truly honoured in Babylon', 'a', 'Ezra 5:17 — "Now therefore, if it seem good to the king, let there be search made in the king''s treasure house, which is there at Babylon, whether it be so, that a decree was made of Cyrus the king to build this house of God at Jerusalem."'),
-- Adults
('Ezra', 5, 'adults', 1, 'How does the phrase "the eye of their God was upon the elders of the Jews" (Ezra 5:5) function theologically in the narrative of opposition?', 'It attributes the failure of Tattenai to stop the work not to the elders'' political skill or Persian law, but to direct divine protection — God''s sovereign watchfulness overriding human opposition', 'It means the Jewish elders were being watched by God for any sinful conduct and were preserved because they were found blameless', 'It is a common idiom meaning the leaders were observant and alert to danger', 'It implies God was displeased with the opposition and was preparing to punish Tattenai immediately', 'a', 'Ezra 5:5 — "But the eye of their God was upon the elders of the Jews, that they could not cause them to cease." The passive construction emphasises divine agency: Tattenai''s authority was overridden not by the elders'' resistance but by God''s active oversight. This verse is the theological hinge of chapters 4-6.'),
('Ezra', 5, 'adults', 2, 'What is the significance of the Jewish elders identifying themselves as "servants of the God of heaven and earth" (Ezra 5:11) to a Persian official?', 'It was a deliberate theological claim: the God they serve is not a local or tribal deity defeated by Nebuchadnezzar but the universal sovereign of all creation — including Persia — and his authority supersedes Tattenai''s', 'It was a standard Jewish formula with no specific apologetic intent', 'It was an appeal to Persian religious pluralism which respected all national deities equally', 'It was a subtle threat implying that the God of heaven would punish Tattenai if he interfered', 'a', 'Ezra 5:11 — "We are the servants of the God of heaven and earth." The title "God of heaven" is used throughout Ezra-Nehemiah when addressing pagans (Ezra 1:2, Neh 1:4, 2:4), asserting universal sovereignty. "And earth" amplifies the claim: this God''s jurisdiction is not bounded by national borders or military defeat.'),
('Ezra', 5, 'adults', 3, 'How does the Jewish elders'' voluntary confession of their fathers'' sin in Ezra 5:12 function as part of their legal defence before Tattenai?', 'It demonstrates theological integrity — they do not deny that God judged them through Nebuchadnezzar but frame the exile as divine discipline now ended, not as evidence that their God was powerless', 'It was a strategic concession designed to gain sympathy from Persian officials who admired religious honesty', 'It undermined their legal case by admitting that God had previously abandoned them', 'It was required by Persian law that petitioners acknowledge any previous judgment against their nation', 'a', 'Ezra 5:12 — "after that our fathers had provoked the God of heaven unto wrath, he gave them into the hand of Nebuchadnezzar." Rather than claiming their God had been defeated, they claim he deliberately used Nebuchadnezzar as his instrument — the same theology as Jeremiah 25:9 — and implicitly argue that the same God can now reverse his judgment.'),
('Ezra', 5, 'adults', 4, 'What is the literary function of the Aramaic letter-within-a-narrative structure in Ezra 5:7-17, and how does it affect the reader''s perception of the events?', 'The verbatim inclusion of official Aramaic correspondence gives the narrative historical credibility and shifts the perspective to how the restoration looked from the outside — the pagan official''s report inadvertently becomes a testimony to Jewish faithfulness and the legitimacy of their project', 'The Aramaic section was inserted by a later editor who had access to Persian archives and had no original connection to the Hebrew narrative', 'The letter format slows the narrative to signal that the legal question, not the building, is the primary concern of chapters 5-6', 'The Aramaic language was chosen to show that the restoration had become a matter of universal rather than merely Israelite concern', 'a', 'Ezra 5:7-17 is in Aramaic (continuing from 4:8), the language of Persian imperial administration. The shift to Aramaic for official documents throughout Ezra 4-6 is a literary device: the reader sees the restoration validated not just by Hebrew theological reflection but by the documentary evidence of the empire itself.'),
('Ezra', 5, 'adults', 5, 'How does the mention of "a great king of Israel" (Ezra 5:11) by the Jewish elders connect the temple restoration to Davidic covenant promises?', 'By identifying Solomon (the builder) as "a great king of Israel" rather than naming him, the elders invoke the Davidic covenant context of the temple — the house built by the Davidic king must be rebuilt under Davidic leadership (Zerubbabel)', 'The reference to "a great king" was deliberately vague to avoid Persian concern about Israelite kingship claims', 'The elders were referring to David rather than Solomon since David first conceived the temple', 'The phrase "great king of Israel" was a common title applied to any successful Israelite ruler without specific Davidic significance', 'a', 'Ezra 5:11 — "a great king of Israel builded and set up." 1 Kings 6:1 records Solomon building the temple in the 480th year after the Exodus. The elders'' description connects temple and Davidic kingship without triggering Persian suspicion about political restoration — a delicate rhetorical achievement.'),
('Ezra', 5, 'adults', 6, 'What does the fact that Tattenai''s investigation is fair and fact-finding (Ezra 5:3-17) rather than immediately punitive reveal about God''s providence in the situation?', 'God arranged that the official who encountered the building project was one who followed proper imperial procedure — seeking verification rather than stopping work by force — allowing the legitimate decree of Cyrus to be the means of vindication', 'Tattenai was personally sympathetic to the Jews and deliberately gave them a favourable hearing', 'Persian law required all governors to investigate rather than act unilaterally, so Tattenai had no choice', 'The Jews had bribed Tattenai to conduct a lenient investigation', 'a', 'Ezra 5:3-5 — Tattenai asks "Who hath commanded you?" but does not stop the work while awaiting Darius''s reply. Contrast with Artaxerxes in 4:21 who ordered immediate cessation. The difference in governors'' responses is part of the providential unfolding: God positioned a fair-minded official at the moment the work resumed.'),
('Ezra', 5, 'adults', 7, 'What is the significance of Zerubbabel''s role in Ezra 5 being described in Haggai 2:23 as "my servant...a signet" — how does this messianic language connect to the temple-building narrative?', 'Zerubbabel as signet reverses the curse on Jehoiachin (Jeremiah 22:24) — where God said he would pluck off the Davidic signet ring — showing the restoration of the Davidic line through Zerubbabel is itself a sign of messianic promise', 'The signet language in Haggai is purely honorific and has no connection to the Jeremiah curse', 'Zerubbabel''s role as signet meant he was appointed as the official seal-keeper of Persian documents for the province', 'The messianic language applies only to Zerubbabel''s political role as governor, not to any broader eschatological significance', 'a', 'Haggai 2:23 — "I will make thee as a signet: for I have chosen thee, saith the LORD of hosts." Jeremiah 22:24 — "though Coniah...were the signet upon my right hand, yet would I pluck thee thence." Zerubbabel, a descendant of Jehoiachin (Coniah), represents the reversal of that curse — the Davidic signet restored in the generation of the temple''s rebuilding.'),
('Ezra', 5, 'adults', 8, 'How does the interplay between prophetic initiative (Haggai and Zechariah) and legal process (Tattenai''s investigation) in Ezra 5 model the relationship between divine word and human institution in God''s purposes?', 'God''s word through the prophets restarted the work (v.1-2) and God''s eye protected it (v.5), but his purposes were also advanced through the legitimate imperial investigation — the two streams converge to vindicate the restoration through both spiritual and legal means', 'The prophets'' initiative made the legal process irrelevant — God would have protected the work regardless of what Tattenai found', 'The legal process was the primary cause of the resumption; the prophets merely provided moral encouragement', 'The two streams are in tension — the prophets urged disobedience to Persian authority while Tattenai represented legitimate oversight', 'a', 'Ezra 5:1-2 (prophetic word), 5:5 (divine eye), 5:17 (legal investigation requesting Cyrus''s decree) — all three work together. The prophets galvanise obedience; God''s eye protects the work; the legal system becomes the instrument of vindication. Ezra-Nehemiah consistently presents God''s purposes advancing through the convergence of prophetic word, covenant faithfulness, and providentially directed human institutions.');

-- ═══ Ezra Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 6, 'kids', 1, 'Where was the scroll with Cyrus''s decree found when Darius ordered a search?', 'In the palace at Achmetha in the province of the Medes', 'In the treasury of Babylon', 'In the library of Jerusalem', 'In the temple records of Persia', 'a', 'Ezra 6:2 — "And there was found at Achmetha, in the palace that is in the province of the Medes, a roll, and therein was a record thus written."'),
('Ezra', 6, 'kids', 2, 'When the temple was finished, what feast did the people of Israel celebrate?', 'The Passover', 'The feast of trumpets', 'The feast of weeks', 'The day of atonement', 'a', 'Ezra 6:19 — "And the children of the captivity kept the passover upon the fourteenth day of the first month."'),
('Ezra', 6, 'kids', 3, 'What did the people feel when the temple was dedicated to God?', 'Joy, because God had turned the heart of the king of Assyria unto them to strengthen their hands', 'Sadness because the temple was smaller than Solomon''s', 'Fear because the enemies were still around them', 'Confusion because they had forgotten how to perform the sacrifices', 'a', 'Ezra 6:22 — "And kept the feast of unleavened bread seven days with joy: for the LORD had turned the heart of the king of Assyria unto them, to strengthen their hands in the work of the house of God, the God of Israel."'),
-- Teens
('Ezra', 6, 'teens', 1, 'What dimensions did the scroll record for Cyrus''s decree regarding the temple?', 'The height threescore cubits and the breadth threescore cubits', 'The height forty cubits and the breadth twenty cubits', 'The height a hundred cubits and the breadth fifty cubits', 'The height seventy cubits and the breadth thirty cubits', 'a', 'Ezra 6:3 — "In the first year of Cyrus the king the same Cyrus the king made a decree concerning the house of God at Jerusalem, Let the house be builded, the place where they offered sacrifices, and let the foundations thereof be strongly laid; the height thereof threescore cubits, and the breadth thereof threescore cubits."'),
('Ezra', 6, 'teens', 2, 'What did Darius command should happen to anyone who altered his decree about the temple building?', 'A timber shall be pulled from his house and he shall be hanged thereon and his house shall be made a dunghill', 'He shall be banished from the empire and all his goods forfeited', 'He shall be cast into the furnace of fire', 'He shall pay a fine of one hundred talents of silver to the treasury', 'a', 'Ezra 6:11 — "Also I have made a decree, that whosoever shall alter this word, let timber be pulled down from his house, and being set up, let him be hanged thereon; and let his house be made a dunghill for this."'),
('Ezra', 6, 'teens', 3, 'What did Darius command should be given daily to the priests in Jerusalem from the royal tribute?', 'Wheat, salt, wine, and oil without fail', 'Gold and silver for the temple furnishings', 'Lambs, bullocks, and rams for the offerings at their own expense', 'Cedar and stone for the continued maintenance of the temple', 'a', 'Ezra 6:9 — "And that which they have need of, both young bullocks, and rams, and lambs, for the burnt offerings of the God of heaven, wheat, salt, wine, and oil...let it be given them day by day without fail."'),
('Ezra', 6, 'teens', 4, 'In what year and month was the temple finished?', 'The third day of the month Adar, in the sixth year of Darius', 'The first day of the month Nisan, in the second year of Darius', 'The fifteenth day of the seventh month, in the fourth year of Darius', 'The tenth day of the first month, in the seventh year of Darius', 'a', 'Ezra 6:15 — "And this house was finished on the third day of the month Adar, which was in the sixth year of the reign of Darius the king."'),
('Ezra', 6, 'teens', 5, 'How many animals were offered at the dedication of the temple?', 'An hundred bullocks, two hundred rams, four hundred lambs, and for a sin offering twelve he goats', 'A thousand bullocks, five hundred rams, and a hundred lambs', 'Seventy bullocks, ninety rams, and two hundred lambs', 'Fifty bullocks, a hundred rams, and three hundred lambs', 'a', 'Ezra 6:17 — "And offered at the dedication of this house of God an hundred bullocks, two hundred rams, four hundred lambs; and for a sin offering for all Israel, twelve he goats, according to the number of the tribes of Israel."'),
-- Adults
('Ezra', 6, 'adults', 1, 'What is the theological irony in Darius''s decree in Ezra 6:9-10 that the Persian treasury must fund the daily offerings so "that they may offer sacrifices of sweet savours unto the God of heaven, and pray for the life of the king"?', 'A pagan king unwittingly becomes the sponsor of Israel''s covenant worship — funding the very sacrifices through which the God of Israel, not the Persian gods, is petitioned on behalf of the empire, thus making Persian power serve Yahweh''s purposes', 'It was a routine Persian policy of funding subject peoples'' religious practices with no theological significance', 'It shows Darius had converted to worshipping the God of heaven and sought his personal blessing', 'It indicates the Jews were using the prayer obligation as a diplomatic tool to secure ongoing Persian support', 'a', 'Ezra 6:9-10 — "wheat, salt, wine, and oil...let it be given them day by day without fail: That they may offer sacrifices of sweet savours unto the God of heaven, and pray for the life of the king." The same God who sent Israel into exile through Nebuchadnezzar is now funded by Persia''s treasury — a complete reversal of national fortunes operating through pagan imperial machinery.'),
('Ezra', 6, 'adults', 2, 'How does the finding of Cyrus''s decree in Achmetha (Ezra 6:2) function as a plot reversal and what does it reveal about the nature of God''s providence?', 'What the adversaries intended as a decisive legal challenge against the Jews becomes the mechanism of their vindication — the search they demanded produces the very document that mandates the temple''s completion at Persian expense', 'The finding of the decree was a lucky coincidence that God used opportunistically', 'The decree was placed in Achmetha by Persian scribes who were secretly sympathetic to the Jews', 'The legal search was unnecessary since Zerubbabel had his own copy of Cyrus''s original decree', 'a', 'Ezra 5:17 — the adversaries asked Darius to search for Cyrus''s decree hoping it would not be found or would be superseded. Ezra 6:2-5 — it was found and confirmed the Jews'' entire position. The adversaries'' own legal strategy became the instrument of their defeat, a reversal pattern recurring throughout Esther and Daniel.'),
('Ezra', 6, 'adults', 3, 'What is the significance of Darius''s prayer-request in Ezra 6:10 — "and pray for the life of the king and of his sons" — within the broader theology of Ezra-Nehemiah?', 'It fulfils Jeremiah''s instruction to pray for Babylon (Jeremiah 29:7) and establishes Israel''s covenant vocation as a priestly people whose intercession blesses even the nations that hold power over them', 'It was a legal obligation extracted from the Jews as the price of Persian support, with no voluntary or theological dimension', 'It shows Darius feared Israel''s God and was seeking personal protection through Jewish prayer', 'It was standard Near Eastern contractual language requiring subject peoples to pray for the king in exchange for religious freedom', 'a', 'Ezra 6:10 — "pray for the life of the king and of his sons." Jeremiah 29:7 — "seek the peace of the city...and pray unto the LORD for it." Israel''s priestly vocation — to be a blessing to the nations through intercession — is ironically maintained even through the mechanisms of imperial patronage.'),
('Ezra', 6, 'adults', 4, 'What is the theological significance of offering twelve he-goats "according to the number of the tribes of Israel" (Ezra 6:17) at the dedication when only two and a half tribes had returned?', 'The twelve-tribe sin offering declares that the returned community represents all Israel — the restoration is not merely partial but claims the full covenant identity of the twelve-tribe nation, anticipating the complete future restoration', 'It was a legal requirement that sin offerings must account for all twelve tribes regardless of who was present', 'It shows the community was confused about how many tribes had actually returned', 'It was a symbolic gesture of goodwill toward the ten northern tribes who remained scattered', 'a', 'Ezra 6:17 — "twelve he goats, according to the number of the tribes of Israel." The returned community was numerically from Judah, Benjamin, and Levi, yet they offered for all twelve. This theological claim — that the remnant represents the whole — is foundational to the post-exilic community''s self-understanding and echoes Ezekiel''s vision of the restored twelve-tribe nation (Ezekiel 47-48).'),
('Ezra', 6, 'adults', 5, 'How does Ezra 6:14 — "they builded, and finished it, according to the commandment of the God of Israel, and according to the commandment of Cyrus, and Darius, and Artaxerxes" — present the relationship between divine and human authority in the completion of the temple?', 'It places God''s commandment first and the three Persian kings'' decrees as subordinate instruments — the primary cause is divine; the human decrees are means by which God''s purpose was accomplished', 'It presents the three kings as co-equal with God in the temple''s completion, reflecting Persian royal theology', 'It shows the author was uncertain whether God or the Persians deserved primary credit and listed all four equally', 'It indicates the temple was primarily a Persian building project that the Jews sanctified through their worship', 'a', 'Ezra 6:14 — "according to the commandment of the God of Israel, and according to the commandment of Cyrus, and Darius, and Artaxerxes." The divine commandment is listed first; the royal decrees follow as its instruments. This verse is the theological summary of the entire temple-building narrative in Ezra 1-6.'),
('Ezra', 6, 'adults', 6, 'What is the connection between the Passover celebration in Ezra 6:19-22 and the original Exodus Passover, and what theological statement does this parallel make?', 'As the first Passover marked deliverance from Egypt and the beginning of Israel''s national life, the restored Passover marks the end of the Babylonian captivity and the beginning of the second Exodus — the restoration is a genuine redemptive event parallel to the Exodus', 'The Passover was observed only because it fell within the calendar period after the dedication with no special theological significance', 'The connection to the Exodus Passover was secondary; the restored Passover primarily commemorated the return from Babylon', 'The two Passovers cannot be compared since the restored one lacked the lamb and bitter herbs of the original', 'a', 'Ezra 6:19-20 — "the children of the captivity kept the passover upon the fourteenth day of the first month. For the priests and the Levites were purified together, all of them were pure." This mirrors Exodus 12; the purification language echoes the preparation for the first Passover. The restoration is presented as a redemption event on the scale of the Exodus.'),
('Ezra', 6, 'adults', 7, 'Why does Ezra 6:21 specify that those who "had separated themselves unto them from the filthiness of the heathen of the land, to seek the LORD God of Israel" also ate the Passover — what does this say about the boundaries of the covenant community?', 'It shows the post-exilic community was not exclusively ethnic — those who genuinely separated from paganism and sought the LORD were included, reflecting the same missionary theology as Ruth and the sojourner provisions of the Torah', 'It shows the community relaxed its genealogical requirements after the temple dedication as a gesture of goodwill to neighbours', 'It is evidence that the separation policy of Ezra 9-10 was not yet in place and was a later development', 'It refers only to Israelites of the northern tribes who had mixed with foreign populations and purified themselves', 'a', 'Ezra 6:21 — "and all such as had separated themselves unto them from the filthiness of the heathen of the land...did eat." The criterion for Passover participation was not exclusively genealogical but spiritual — separation from idolatry and commitment to seek the LORD, consistent with Numbers 9:14 which permitted the sojourner to keep Passover.'),
('Ezra', 6, 'adults', 8, 'How does Ezra 6:22''s description of Darius as "the king of Assyria" — when he was actually king of Persia — function in the theological narrative of Ezra?', 'It identifies Darius with the entire succession of world empires that had oppressed Israel (Assyria, Babylon, Persia), using "Assyria" as a theological title for the foreign power, and declares that even this power has been turned by God to serve Israel''s restoration', 'It is a scribal error where the author confused Darius with an earlier Assyrian king', 'It was a Persian royal title that Darius inherited through conquest of the former Assyrian territories', 'It reflects the author''s limited geographical knowledge of the Persian empire''s eastern territories', 'a', 'Ezra 6:22 — "the LORD had turned the heart of the king of Assyria unto them." Darius was king of Persia; calling him king of Assyria is a deliberate theological typology: the same God who once used Assyria as his rod of judgment (Isaiah 10:5) now turns the successor empire''s heart to bless his people. The title signals that no world power stands outside God''s sovereign direction.');

-- ═══ Ezra Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 7, 'kids', 1, 'What was Ezra''s job that made him important to the people?', 'He was a ready scribe in the law of Moses', 'He was the high priest in Jerusalem', 'He was the governor of the province', 'He was a builder of the temple walls', 'a', 'Ezra 7:6 — "This Ezra went up from Babylon; and he was a ready scribe in the law of Moses, which the LORD God of Israel had given."'),
('Ezra', 7, 'kids', 2, 'What had God given Ezra that helped him on his journey?', 'The good hand of his God was upon him', 'A large army to protect him', 'A map drawn by the Persian king', 'Silver and gold more than any other traveller', 'a', 'Ezra 7:6 — "The king granted him all his request, according to the hand of the LORD his God upon him."'),
('Ezra', 7, 'kids', 3, 'What three things did Ezra set his heart to do according to Ezra 7:10?', 'To seek the law of the LORD, to do it, and to teach Israel statutes and judgments', 'To build the temple, repair the walls, and gather the people', 'To pray, fast, and offer sacrifices for the people', 'To read the scriptures, copy them, and distribute them throughout Israel', 'a', 'Ezra 7:10 — "For Ezra had prepared his heart to seek the law of the LORD, and to do it, and to teach in Israel statutes and judgments."'),
-- Teens
('Ezra', 7, 'teens', 1, 'From whom was Ezra descended, according to the genealogy in Ezra 7:1-5?', 'Aaron the chief priest through Seraiah', 'David through the tribe of Judah', 'Moses through the tribe of Levi', 'Zerubbabel through the family of Shealtiel', 'a', 'Ezra 7:1,5 — "Now after these things, in the reign of Artaxerxes king of Persia, Ezra the son of Seraiah...the son of Aaron the chief priest."'),
('Ezra', 7, 'teens', 2, 'In which year of King Artaxerxes did Ezra go up to Jerusalem?', 'The seventh year of Artaxerxes', 'The twentieth year of Artaxerxes', 'The second year of Artaxerxes', 'The fourteenth year of Artaxerxes', 'a', 'Ezra 7:7-8 — "And there went up some of the children of Israel...in the seventh year of Artaxerxes the king. And he came to Jerusalem in the fifth month, which was in the seventh year of the king."'),
('Ezra', 7, 'teens', 3, 'What did the letter of Artaxerxes say about any of the people of Israel who were willing to go to Jerusalem with Ezra?', 'I make a decree, that all they of the people of Israel, and of his priests and Levites, in my realm, which are minded of their own freewill to go up to Jerusalem, go with thee', 'Only the priests and Levites were permitted to travel with Ezra', 'They must receive permission from their local governor before joining Ezra''s company', 'Only men of Judah and Benjamin who could prove their genealogy could go with Ezra', 'a', 'Ezra 7:13 — "I make a decree, that all they of the people of Israel, and of his priests and Levites, in my realm, which are minded of their own freewill to go up to Jerusalem, go with thee."'),
('Ezra', 7, 'teens', 4, 'What authority did Artaxerxes give Ezra regarding the teaching of God''s laws to those who did not know them?', 'Whosoever will not do the law of thy God and the law of the king, let judgment be executed speedily upon him', 'Ezra was given authority to appoint judges and priests throughout the province', 'Ezra was authorised to collect taxes to fund the teaching ministry throughout the region', 'Ezra was permitted to teach only in Jerusalem and not in the surrounding provinces', 'a', 'Ezra 7:26 — "And whosoever will not do the law of thy God, and the law of the king, let judgment be executed speedily upon him, whether it be unto death, or to banishment, or to confiscation of goods, or to imprisonment."'),
('Ezra', 7, 'teens', 5, 'How did Ezra respond when he read Artaxerxes'' gracious letter, and whom did he bless?', 'He blessed the LORD God of his fathers who had put such a thing as this in the king''s heart', 'He immediately gathered the people and read the letter to them', 'He offered a hundred burnt offerings at the altar in thanksgiving', 'He sent a letter of thanks to Artaxerxes and prepared his journey', 'a', 'Ezra 7:27 — "Blessed be the LORD God of our fathers, which hath put such a thing as this in the king''s heart, to beautify the house of the LORD which is in Jerusalem."'),
-- Adults
('Ezra', 7, 'adults', 1, 'What is the theological significance of the phrase "the hand of the LORD his God was upon him" appearing three times in Ezra 7 (vv.6,9,28)?', 'The triple repetition establishes the governing theme of Ezra''s entire mission: every success — royal favour, safe journey, gathered companions — is attributed not to Ezra''s scholarship or status but to direct divine enabling, creating a theology of grace-sustained service', 'It is a stylistic formula indicating Ezra was a prophet receiving divine revelation', 'It is the author''s way of noting that God intervened supernaturally at three specific crisis points in the chapter', 'The repetition emphasises that Ezra was specially chosen above all other priests and scribes of his generation', 'a', 'Ezra 7:6 — "the hand of the LORD his God upon him"; 7:9 — "the good hand of his God upon him"; 7:28 — "the hand of the LORD my God was upon me." The phrase forms an inclusio around the entire chapter, attributing everything — the king''s favour (v.6), the journey''s completion (v.9), and the gathered companions (v.28) — to God''s enabling hand.'),
('Ezra', 7, 'adults', 2, 'How does the triple description of Ezra''s preparation in Ezra 7:10 — "to seek...to do...to teach" — function as a model for biblical leadership?', 'It establishes a necessary sequence: personal study of God''s word precedes personal obedience, which precedes public teaching — Ezra''s authority as teacher was grounded in his prior integrity as a student and practitioner of the law', 'It shows Ezra''s role was primarily administrative rather than spiritual — the three tasks describe his official duties', 'It indicates Ezra was simultaneously reformer, judge, and priest, reflecting the unique convergence of offices in the post-exilic period', 'It was the standard job description for scribes in the Second Temple period with no particular theological significance', 'a', 'Ezra 7:10 — "Ezra had prepared his heart to seek the law of the LORD, and to do it, and to teach in Israel statutes and judgments." The sequence cannot be reversed: teaching without doing is hypocrisy; doing without seeking is tradition without understanding. This verse is one of the clearest statements of integrated biblical leadership in the Old Testament.'),
('Ezra', 7, 'adults', 3, 'What is the political and theological significance of Artaxerxes designating Ezra to "enquire concerning Judah and Jerusalem, according to the law of thy God which is in thine hand" (Ezra 7:14)?', 'It granted the Torah formal legal standing within the Persian administrative framework for the province of Judah — the law of God became the constitutional basis of Jewish communal life with imperial backing', 'It was a routine Persian religious tolerance policy applying to all ethnic communities in the empire', 'It shows Artaxerxes had personally studied the Torah and recognised its wisdom as a governing document', 'It limited Ezra''s authority to purely religious matters, excluding him from any civil or administrative role', 'a', 'Ezra 7:14,25-26 — Ezra is commissioned to "enquire" (inspect and enforce) according to "the law of thy God" and to appoint judges who know "the laws of thy God." The Torah became the civil code of Yehud (Judah) under Persian imperial authority — a remarkable convergence of divine law and political legitimation.'),
('Ezra', 7, 'adults', 4, 'How does Artaxerxes'' letter specify the limits of silver and gold that Ezra could draw from the royal treasury in Ezra 7:22, and what does this reveal about Persian governance of religious affairs?', 'Precise caps — unto an hundred talents of silver, measures of wheat, baths of wine, baths of oil, and salt without prescribing how much — show Persian patronage was generous but bounded, reflecting a calculated policy of religious support within imperial fiscal limits', 'The limits were set by Ezra himself to avoid the appearance of self-enrichment', 'Artaxerxes set no limits, granting Ezra unlimited access to the royal treasury', 'The limits were the standard Persian temple-maintenance allocation applied to all ethnic shrines in the empire equally', 'a', 'Ezra 7:22 — "Unto an hundred talents of silver, and to an hundred measures of wheat, and to an hundred baths of wine, and to an hundred baths of oil, and salt without prescribing how much." The precise limits show genuine Persian munificence alongside administrative prudence — they are remarkably generous (100 talents of silver was enormous) while remaining bounded.'),
('Ezra', 7, 'adults', 5, 'What does Artaxerxes'' statement "whatsoever is commanded by the God of heaven, let it be diligently done for the house of the God of heaven: for why should there be wrath against the realm of the king and his sons?" (Ezra 7:23) reveal about Persian theology of risk?', 'It reflects a pragmatic fear of offending powerful deities — Artaxerxes supports the God of heaven''s temple not from piety but to avoid divine retribution, yet God uses this fear to accomplish his covenant purposes', 'It shows Artaxerxes had converted to worshipping the God of Israel and feared his judgment from genuine faith', 'It was standard Persian diplomatic language with no actual theological content', 'It reflects the Persian king''s belief that the God of heaven was the most powerful deity and therefore deserved the greatest support', 'a', 'Ezra 7:23 — "for why should there be wrath against the realm of the king and his sons?" Artaxerxes'' motivation is precautionary rather than devotional — he does not want to risk divine anger. Yet this pagan prudence becomes the vehicle of God''s covenant faithfulness, illustrating that God can accomplish his purposes even through imperfect human motivations.'),
('Ezra', 7, 'adults', 6, 'How does the exemption of priests, Levites, and temple servants from all taxes in Ezra 7:24 reflect the social vision of the Torah regarding those who serve God full-time?', 'Numbers 18:20-24 gave the Levites no land inheritance; instead Israel''s tithes supported them. Artaxerxes'' tax exemption achieves a similar result within an imperial framework — those serving God exclusively are freed from competing economic burdens that would compromise their service', 'The tax exemption was a Persian standard benefit for religious professionals of all faiths with no connection to Mosaic provision', 'It shows Artaxerxes was personally generous toward religious workers rather than following any precedent', 'The exemption created a privileged priestly class contrary to the egalitarian spirit of the Torah''s Levitical provisions', 'a', 'Ezra 7:24 — "Also we certify you, that touching any of the priests and Levites, singers, porters, Nethinims, or ministers of this house of God, it shall not be lawful to impose toll, tribute, or custom upon them." Numbers 18:21 — "I have given the children of Levi all the tenth in Israel for an inheritance, for their service." The Persian exemption mirrors the Torah''s provision: those whose full-time calling is God''s service are freed from competing obligations.'),
('Ezra', 7, 'adults', 7, 'What is the canonical function of Ezra 7:27-28 — Ezra''s personal doxology switching from third person narrative to first person — in structuring the book of Ezra?', 'It marks the transition from historical narrative (chapters 1-6, third person) to Ezra''s personal memoir (chapters 7-10, first person), making the shift to first person a theological acknowledgment: all that God did, Ezra himself experienced and testifies to', 'It was an error introduced by a later editor who accidentally inserted Ezra''s private diary into the official narrative', 'It signals that Ezra wrote only chapters 7-10 and the first six chapters were composed by Zerubbabel''s scribes', 'The switch to first person serves only a literary purpose, emphasising Ezra''s humility in not narrating his own story in third person throughout', 'a', 'Ezra 7:27 — "Blessed be the LORD God of our fathers, which hath put such a thing as this in the king''s heart...And I was strengthened as the hand of the LORD my God was upon me." The first-person section begins here. Scholars call this the "Ezra Memoir" (chapters 7-10, plus Nehemiah 8). The switch marks Ezra''s personal testimony as distinct from the communal history of chapters 1-6.'),
('Ezra', 7, 'adults', 8, 'How does Ezra''s Aaronic genealogy in Ezra 7:1-5 establish his authority for the mission described in Ezra 7:10-26, and what does this reveal about the nature of qualifications for biblical leadership?', 'His unbroken Aaronic lineage through Zadok and Phinehas establishes priestly legitimacy, while Ezra 7:10 establishes personal preparation — together they show that genuine spiritual authority combines divine appointment (lineage) with personal character (seeking, doing, teaching)', 'The genealogy was a Persian administrative requirement for any official claiming religious authority in the province', 'His authority rested entirely on Artaxerxes'' commission; the genealogy was secondary and served only to establish his ethnicity', 'The genealogy shows that priestly descent alone was sufficient for authority without the personal preparation described in verse 10', 'a', 'Ezra 7:1-5 provides 16 generations of Aaronic descent ending at Seraiah. Ezra 7:10 adds personal preparation. Together they present a complete picture of biblical leadership qualification: covenant identity (who you are by God''s appointment) combined with personal integrity (what you have prepared yourself to be). Neither alone is sufficient.');

-- ═══ Ezra Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 8, 'kids', 1, 'What did Ezra do at the Ahava river before starting the journey to Jerusalem?', 'He proclaimed a fast so that the people might humble themselves before God and ask for a safe journey', 'He built an altar and offered sacrifices to God', 'He gathered all the silver and gold and counted it carefully', 'He sent messengers ahead to Jerusalem to prepare for their arrival', 'a', 'Ezra 8:21 — "Then I proclaimed a fast there, at the river of Ahava, that we might afflict ourselves before our God, to seek of him a right way for us, and for our little ones, and for all our substance."'),
('Ezra', 8, 'kids', 2, 'Why was Ezra ashamed to ask the king for soldiers to protect them on the journey?', 'He had told the king that the hand of God was upon all those who sought him, and to ask for soldiers would show he did not really trust God', 'He was afraid the king would be angry that Ezra did not trust the Persian army', 'The king had already refused to provide soldiers for religious travelers', 'The soldiers would slow the group down on the long journey', 'a', 'Ezra 8:22 — "For I was ashamed to require of the king a band of soldiers and horsemen to help us against the enemy in the way: because we had spoken unto the king, saying, The hand of our God is upon all them for good that seek him."'),
('Ezra', 8, 'kids', 3, 'What did God give the people on their journey to Jerusalem?', 'He delivered them from the hand of the enemy and from ambushes along the way', 'He sent rain to cool them on the hot desert road', 'He gave them extra food to keep them strong for the journey', 'He caused the enemy armies to flee before they arrived', 'a', 'Ezra 8:31 — "The hand of our God was upon us, and he delivered us from the hand of the enemy, and of such as lay in wait by the way."'),
-- Teens
('Ezra', 8, 'teens', 1, 'What was missing from Ezra''s company when he reviewed the people at the river Ahava?', 'There were no sons of Levi with the group', 'There were no priests among the company that had gathered', 'There were no women or children in the group', 'There were no leaders from the tribe of Judah present', 'a', 'Ezra 8:15 — "I viewed the people, and the priests, and found there none of the sons of Levi."'),
('Ezra', 8, 'teens', 2, 'Where did Ezra send messengers to find Levites to join the company, and who was the chief man there?', 'He sent to the place Casiphia where Iddo was the chief man', 'He sent to Babylon where the chief rabbi Hilkiah led the community', 'He sent to Nippur where the Levitical school was located', 'He sent to Jerusalem where the remaining Levites had already returned', 'a', 'Ezra 8:17 — "And I sent them with commandment unto Iddo the chief at the place Casiphia...that they should bring unto us ministers for the house of our God."'),
('Ezra', 8, 'teens', 3, 'How much silver and gold did Ezra weigh out to the priests before they departed for Jerusalem?', 'Six hundred and fifty talents of silver, silver vessels of an hundred talents, and of gold an hundred talents', 'A thousand talents of silver and fifty talents of gold', 'Five hundred talents of silver and twenty talents of gold', 'Three hundred talents of silver and thirty talents of gold', 'a', 'Ezra 8:26 — "I even weighed unto their hand six hundred and fifty talents of silver, and silver vessels an hundred talents, and of gold an hundred talents."'),
('Ezra', 8, 'teens', 4, 'What did Ezra tell the priests when he gave them charge of the silver and gold?', 'Ye are holy unto the LORD; the vessels are holy also; and the silver and the gold are a freewill offering unto the LORD God of your fathers. Watch ye, and keep them', 'These treasures are the king''s property and you must return them in full on arrival', 'Guard these with your lives for the enemy will try to steal them on the road', 'Count them carefully each evening and keep a written record of every item', 'a', 'Ezra 8:28-29 — "Then I said unto them, Ye are holy unto the LORD; the vessels are holy also; and the silver and the gold are a freewill offering unto the LORD God of your fathers...Watch ye, and keep them, until ye weigh them before the chief of the priests and the Levites."'),
('Ezra', 8, 'teens', 5, 'How many days after arriving in Jerusalem did they wait before weighing the silver, gold, and vessels in the temple?', 'Three days', 'Seven days', 'One day', 'Fourteen days', 'a', 'Ezra 8:32-33 — "And we came to Jerusalem, and abode there three days. Now on the fourth day was the silver and the gold and the vessels weighed in the house of our God by the hand of Meremoth the son of Uriah the priest."'),
-- Adults
('Ezra', 8, 'adults', 1, 'What does the proclaimed fast in Ezra 8:21-23 reveal about Ezra''s theology of prayer and the relationship between stated faith and concrete dependence on God?', 'Ezra had publicly declared God''s protection to Artaxerxes, making it a matter of witness — the fast was therefore both genuine humility before God and a visible act of consistency, refusing to undermine his testimony by seeking human security he had just said was unnecessary', 'The fast was primarily a religious requirement before any significant journey in Second Temple Judaism', 'Ezra proclaimed the fast to demonstrate to his companions that he trusted God, setting an example for the community', 'The fast was a strategic delay to allow Ezra to reconsider whether to ask the king for soldiers after all', 'a', 'Ezra 8:22-23 — "I was ashamed to require of the king a band of soldiers...because we had spoken unto the king, saying, The hand of our God is upon all them for good that seek him...So we fasted and besought our God for this: and he was intreated of us." Ezra''s stated theology committed him to consistent faith; the fast expressed that commitment in action.'),
('Ezra', 8, 'adults', 2, 'How does Ezra''s refusal of a military escort (Ezra 8:22) compare to Nehemiah''s acceptance of a royal guard (Nehemiah 2:9), and what does the comparison reveal about the nature of faith?', 'Both responses were faithful in context: Ezra had made a specific public declaration about God''s protection that required consistency; Nehemiah made no such claim and accepted legitimate means of security — neither passage prescribes universal rejection of human protection', 'Ezra''s refusal was the ideal model and Nehemiah''s acceptance was a lapse of faith', 'The two responses reflect different covenants — Ezra operated under the Mosaic covenant''s promises of protection while Nehemiah operated under a more pragmatic post-exilic arrangement', 'Nehemiah''s acceptance of guards shows he had greater responsibilities and therefore greater need for protection than Ezra''s purely religious mission', 'a', 'Ezra 8:22 — "I was ashamed to require...soldiers." Nehemiah 2:9 — "Now the king had sent captains of the army and horsemen with me." The difference lies in stated commitments, not in the level of faith. Both men trusted God; Ezra''s prior testimony required a visible demonstration of that trust; Nehemiah had made no such statement and used available means without contradiction.'),
('Ezra', 8, 'adults', 3, 'What is the significance of weighing the treasures both before departure (Ezra 8:26-27) and upon arrival (Ezra 8:33-34)?', 'The double weighing established a verifiable chain of custody that demonstrated the integrity of those entrusted with holy things — the community''s stewardship of God''s resources was transparent and accountable at both ends of the transaction', 'The weighing was a Persian administrative requirement for all transfers of royal funds between provinces', 'The arrival weighing was to check for loss due to theft on the road and identify any responsible priests', 'The double weighing was symbolic — once before God and once before men — to consecrate the treasures to their holy use', 'a', 'Ezra 8:26,33-34 — Treasures weighed to the priests before departure; "on the fourth day was the silver and the gold and the vessels weighed...by number and by weight of every one: and all the weight was written at that time." The meticulous accountability reflects the principle that those handling holy things must be beyond reproach.'),
('Ezra', 8, 'adults', 4, 'What does Ezra''s characterization of the priests as "holy unto the LORD" and the vessels as "holy also" (Ezra 8:28) reveal about his understanding of consecration?', 'It treats the bearers of holy things as themselves consecrated by the task — their identity and responsibility are inseparable, meaning the integrity of the priests personally is part of what makes the offering acceptable', 'It was a priestly ordination formula pronounced before any sacred transport of temple objects', 'It distinguished the priests from the Levites and non-priests in the company by granting them higher ceremonial status for the journey', 'It refers only to the ritual purity required before handling sacred objects, not to a broader theology of consecration', 'a', 'Ezra 8:28 — "Ye are holy unto the LORD; the vessels are holy also." The coupling of persons and objects in the same consecration language reflects Exodus 19:6 — "ye shall be unto me...an holy nation." The priests'' holiness and the vessels'' holiness are presented as commensurate: to handle holy things requires holy persons.'),
('Ezra', 8, 'adults', 5, 'How does the list of family heads in Ezra 8:1-14 function similarly to the list in Ezra 2, and what does the repetition of this literary form signal?', 'Both lists serve as community charters, establishing the legitimacy and completeness of each wave of returnees; the Ezra 8 list shows God''s restoration is ongoing — a second movement of return, smaller but equally documented, continuing the covenant community''s reconstitution', 'The Ezra 8 list is simply a record for Persian administrative purposes with no theological parallel to Ezra 2', 'The repetition shows the author lacked originality and used the same formula for different occasions', 'The two lists are from the same event and were duplicated by a later editor who misidentified the occasion', 'a', 'Ezra 2:1 — "These are the children of the province that went up"; Ezra 8:1 — "These are now the chief of their fathers, and this is the genealogy of them that went up with me." The parallel structure presents Ezra''s return as a second wave of the same restoration movement, each wave authenticated by the same documentary legitimacy.'),
('Ezra', 8, 'adults', 6, 'What does the fact that Levites had to be specially recruited (Ezra 8:15-20) — fewer than 300 joining Ezra''s company of thousands — suggest about the post-exilic Levitical situation?', 'It reflects a historical reluctance among Levites to return — perhaps because life in Babylon was comfortable or their Levitical role in a diaspora community gave them security — and shows Ezra valued correct worship enough to delay the journey until proper liturgical personnel were gathered', 'It shows the Levites had been specifically forbidden by Persian law from emigrating as a group', 'It reflects a shortage of Levites in Babylon because they had all returned in the first wave under Zerubbabel', 'It shows the Levites were not enthusiastic about Ezra''s leadership and many preferred to stay in Babylon in protest', 'a', 'Ezra 8:15-16 — "I viewed the people, and the priests, and found there none of the sons of Levi. Then sent I for Eliezer...men of understanding." That only 38 Levites (v.18-19) joined thousands of returnees suggests assimilation and comfort in Babylon had diminished Levitical commitment to the land. Ezra''s deliberate recruitment shows the temple''s worship required qualified ministers, not just willing volunteers.'),
('Ezra', 8, 'adults', 7, 'How does "the good hand of our God upon us" in Ezra 8:18 — referring specifically to the finding of Levites — extend the theological phrase established in chapter 7?', 'It shows God''s hand was not only in royal favour (7:6) and safe journeying (7:9) but also in providential provision of personnel — every specific need of the restoration mission was met by the same divine enabling hand', 'The phrase in chapter 8 is a different idiom from chapter 7 and should not be connected', 'It shows Iddo the chief man was himself directed by God''s hand to send qualified Levites', 'The phrase refers specifically to the skill of the Levites who were found, not to any divine activity', 'a', 'Ezra 7:6,9,28; 8:18,22,31 — "the hand of the LORD" or "the hand of our God" appears six times across chapters 7-8. Each instance attributes a specific, concrete provision to divine action: the king''s favour, the journey''s timing, the Levites'' availability, the fasting''s answer, and the journey''s safety. The cumulative effect is a theology of comprehensive divine providence.'),
('Ezra', 8, 'adults', 8, 'What does the offering of burnt offerings and sin offerings upon arrival in Jerusalem (Ezra 8:35) reveal about the spiritual self-understanding of the returning exiles?', 'The sin offerings "for all Israel" (twelve bullocks paralleling Ezra 6:17''s twelve he-goats) declare that the returning company represents the whole nation, still in need of atonement, coming before God not with moral achievement but with sacrifice — a profoundly humble opening to the restoration mission', 'The offerings were a legally required dedication ceremony before the returnees could legally reside in Jerusalem', 'The sin offerings were for the specific sins committed during the Babylonian exile and had no forward-looking significance', 'The burnt offerings celebrated arrival safely but the sin offerings were unrelated, being part of the regular festival calendar', 'a', 'Ezra 8:35 — "Also the children of those that had been carried away...offered burnt offerings unto the God of Israel, twelve bullocks for all Israel, ninety and six rams...twelve he goats for a sin offering." The twelve-tribe symbolism (cf. 6:17) recurs: the restored community''s first act is corporate atonement, confessing that return does not erase the need for forgiveness — a fitting prologue to the crisis of Ezra 9.');

-- ═══ Ezra Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 9, 'kids', 1, 'What terrible news did the princes bring to Ezra that made him very sad?', 'The people of Israel had not separated themselves from the peoples of the lands but had taken their daughters as wives', 'The temple had been damaged by the enemies of Judah', 'The Persian king had cancelled his decree to help the Jews', 'The people had stopped offering sacrifices at the temple', 'a', 'Ezra 9:1-2 — "The princes came to me, saying, The people of Israel, and the priests, and the Levites, have not separated themselves from the people of the lands...For they have taken of their daughters for themselves, and for their sons."'),
('Ezra', 9, 'kids', 2, 'When Ezra heard the bad news what did he do with his clothing?', 'He rent his garment and his mantle and sat down astonied', 'He put on sackcloth and ashes and went to the temple to pray', 'He tore only his outer robe and wept loudly in the street', 'He changed into white clothing as a sign of mourning', 'a', 'Ezra 9:3 — "And when I heard this thing, I rent my garment and my mantle, and plucked off the hair of my head and of my beard, and sat down astonied."'),
('Ezra', 9, 'kids', 3, 'In his prayer what did Ezra say about Israel''s sins — were they small or big?', 'Our iniquities are increased over our head and our trespass is grown up unto the heavens', 'Our sins are many but God''s mercy is greater than all of them', 'We have sinned a little and God will quickly forgive us', 'Our trespass is hidden from God because it happened in secret', 'a', 'Ezra 9:6 — "O my God, I am ashamed and blush to lift up my face to thee, my God: for our iniquities are increased over our head, and our trespass is grown up unto the heavens."'),
-- Teens
('Ezra', 9, 'teens', 1, 'Which specific peoples did Ezra''s report say the Israelites had mixed with through intermarriage?', 'The Canaanites, Hittites, Perizzites, Jebusites, Ammonites, Moabites, Egyptians, and Amorites', 'The Babylonians, Persians, Medes, and Greeks', 'The Philistines, Edomites, and Syrians', 'The Arabians, Midianites, and peoples of the sea coast', 'a', 'Ezra 9:1 — "The people of Israel, and the priests, and the Levites, have not separated themselves from the people of the lands...even the Canaanites, the Hittites, the Perizzites, the Jebusites, the Ammonites, the Moabites, the Egyptians, and the Amorites."'),
('Ezra', 9, 'teens', 2, 'Ezra sat astonied until the evening sacrifice. What did he do then?', 'He fell upon his knees and spread out his hands unto the LORD his God and made confession', 'He called the princes together and read the law of Moses to them', 'He sent messengers throughout Jerusalem calling the people to assemble', 'He wrote a letter to Artaxerxes asking for guidance on how to handle the situation', 'a', 'Ezra 9:5 — "And at the evening sacrifice I arose up from my heaviness; and having rent my garment and my mantle, I fell upon my knees, and spread out my hands unto the LORD my God."'),
('Ezra', 9, 'teens', 3, 'What did Ezra say God had done for the people after the captivity, despite their sins?', 'God had left them a remnant and given them a nail in his holy place and enlightened their eyes and given them a little reviving', 'God had forgiven all their sins and restored them to full blessing', 'God had destroyed their enemies and given them peace on every side', 'God had raised up prophets to guide them and protect them from all danger', 'a', 'Ezra 9:8 — "And now for a little space grace hath been shewed from the LORD our God, to leave us a remnant to escape, and to give us a nail in his holy place, that our God may lighten our eyes, and give us a little reviving in our bondage."'),
('Ezra', 9, 'teens', 4, 'What does Ezra''s prayer say that God had commanded them not to do regarding the people of these abominations?', 'That they should not give their daughters to these peoples'' sons nor take their daughters for their sons and never seek their peace or wealth forever', 'That they should drive all such peoples out of the land by force', 'That they should build a wall around Jerusalem to keep foreigners out', 'That they should not trade with such peoples or allow them to live in the cities of Judah', 'a', 'Ezra 9:12 — "Now therefore give not your daughters unto their sons, neither take their daughters unto your sons, nor seek their peace or their wealth for ever: that ye may be strong, and eat the good of the land, and leave it for an inheritance to your children for ever."'),
('Ezra', 9, 'teens', 5, 'Ezra ended his prayer asking whether God would be so angry as to consume what, since there could be no remaining after they had done such things?', 'There is no remaining and none escaping since they had exceeded the iniquity that left no remnant', 'God would be so angry as to destroy the temple that they had just rebuilt', 'The Persian king would be made so angry by God that he would withdraw all support', 'The land would be consumed with drought and famine as punishment for their sin', 'a', 'Ezra 9:14-15 — "Should we again break thy commandments, and join in affinity with the people of these abominations? wouldest not thou be angry with us till thou hadst consumed us, so that there should be no remnant nor escaping? O LORD God of Israel, thou art righteous: for we remain yet escaped, as it is this day: behold, we are before thee in our trespasses."'),
-- Adults
('Ezra', 9, 'adults', 1, 'What is the nature of Ezra''s identificatory prayer in chapter 9 — he uses "we" and "our" throughout though he personally had just arrived — and what theological tradition does this reflect?', 'It reflects the Hebrew tradition of corporate solidarity: the leader identifies with the community''s sin as his own, praying as one guilty party rather than an outraged outsider, paralleling Moses (Exodus 32:31), Daniel (Daniel 9:5), and Nehemiah (Nehemiah 1:6)', 'It reflects Ezra''s personal guilt since he had also taken a foreign wife before his return', 'It was a rhetorical device to avoid offending those who had sinned by appearing to accuse them', 'It shows Ezra believed the sin of the fathers was transmitted to all subsequent generations as personal guilt', 'a', 'Ezra 9:6-7 — "our iniquities...our trespass...our kings, our priests." Ezra arrived in Jerusalem only weeks before this prayer (8:32-33) and had no personal involvement in the intermarriages. His use of "we" deliberately identifies with the nation in covenant solidarity, the same posture as Daniel 9:5 — "We have sinned."'),
('Ezra', 9, 'adults', 2, 'How does the "nail in his holy place" (Ezra 9:8) function as a metaphor for the restored community''s precarious but real security?', 'A nail (yated) was a tent peg — the restored community had only a small, insecure foothold, but even this fragile restoration was a gift of grace that could be torn out if they repeated the sins that caused the exile', 'The nail metaphor referred to the dedication of the temple cornerstone as a permanent foundation', 'It was a military metaphor for a fortified position — the temple mount as a defensible stronghold', 'The nail image came from the prophecy of Isaiah 22:23 where the nail represented the Davidic dynasty''s permanence', 'a', 'Ezra 9:8 — "to give us a nail in his holy place." Isaiah 22:23-25 uses the same yated (nail/peg) metaphor for a firmly fixed thing that can be "cut down and fall." Ezra''s use captures the paradox of the restoration: secure enough to be called a nail, but precarious enough to be threatened by covenant unfaithfulness.'),
('Ezra', 9, 'adults', 3, 'How does Ezra''s reference to "the servant of Moses" in Ezra 9:11 function in establishing the authority of the prohibition against intermarriage?', 'By attributing the prohibition to Moses'' prophetic command, Ezra grounds the contemporary crisis in the foundational covenant law (Deuteronomy 7:3-4), establishing continuity between the Sinai covenant and the post-exilic community''s obligations', 'It was a rhetorical appeal designed to shame the people by reminding them of a teacher greater than Ezra', 'It shows Ezra was unsure of his own prophetic authority and deferred to Moses to avoid personal responsibility', 'It suggests Ezra was citing a specific letter from Moses found in the temple records rather than the canonical Torah', 'a', 'Ezra 9:11 — "Which thou hast commanded by thy servants the prophets, saying, The land...is an unclean land with the filthiness of the people of the lands." Deuteronomy 7:3-4 — "Neither shalt thou make marriages with them...For they will turn away thy son from following me." Ezra''s prayer presents the current crisis as a direct violation of Moses'' specific command.'),
('Ezra', 9, 'adults', 4, 'What is the theological relationship between the exile and the restoration in Ezra 9:7-9, and how does Ezra use this relationship to intensify the urgency of the intermarriage crisis?', 'Ezra argues that the exile was God''s judgment for exactly such covenant unfaithfulness, and the restoration was pure unmerited grace; therefore repeating the same sins while enjoying that grace would be a greater offense than the original violation — ingratitude compounding infidelity', 'He uses the exile and restoration only as historical background without drawing a direct moral comparison to the current crisis', 'He argues that the exile is now complete and the people are free from the covenant warnings attached to it', 'He presents the restoration as a reward for the faithfulness of the exiles in Babylon rather than as grace, making the intermarriage crisis a betrayal of earned blessing', 'a', 'Ezra 9:7-8 — "For our iniquities have we, our kings, and our priests, been delivered...unto this day...And now for a little space grace hath been shewed from the LORD our God." The contrast between "delivered because of sin" (v.7) and "grace given" (v.8) sets up the terrible logic of v.14: to sin again after grace would be to court total destruction, not just partial judgment.'),
('Ezra', 9, 'adults', 5, 'How does Ezra 9:2 — "the holy seed have mingled themselves with the people of those lands" — use the concept of holiness as the basis for the separation principle?', 'Holy seed (zera haqqodesh) frames Israel''s covenant identity as a set-apart lineage called to embody God''s character among the nations; intermarriage that imported idolatrous influence threatened this distinctive witness — the issue was theological contamination, not racial purity', 'Holy seed was a genetic category ensuring the Levitical bloodlines remained uncontaminated for priestly service', 'The phrase was a post-exilic innovation with no Mosaic precedent, invented by Ezra to justify his reforms', 'Holy seed referred only to the Levites and priests; the prohibition on intermarriage did not apply to lay Israelites', 'a', 'Ezra 9:2 — "for they have taken of their daughters for themselves, and for their sons: so that the holy seed have mingled themselves with the people of those lands." Deuteronomy 7:6 — "thou art an holy people unto the LORD thy God." The "seed" language echoes Isaiah 6:13''s "holy seed" as the surviving remnant of God''s purposes. The concern was covenantal contamination through the adoption of foreign religious practices (Deut 7:4 — "they will turn away thy son from following me").'),
('Ezra', 9, 'adults', 6, 'What does the posture of mourning Ezra adopted — sitting astonished, tearing garments, pulling hair, kneeling, spreading hands — reveal about the nature of effective intercessory leadership?', 'Ezra''s visible, physical grief before praying mobilised the community around a shared recognition of sin — his mourning became a prophetic act that drew others into corporate lament before any solution was proposed, creating the emotional and spiritual conditions for genuine repentance', 'The mourning was purely private and personal, with no intended public effect on the community', 'Ezra''s mourning was strategically calculated to shame the offenders into compliance with his forthcoming decree', 'The physical mourning rituals were required by Mosaic law before any leader could approach God with corporate intercession', 'a', 'Ezra 9:3-4 — "I rent my garment and my mantle, and plucked off the hair of my head and of my beard, and sat down astonied...Then were assembled unto me every one that trembled at the words of the God of Israel." His mourning became a gathering point: the community''s conscience was awakened not by Ezra''s speech but by his grief.'),
('Ezra', 9, 'adults', 7, 'How does Ezra''s prayer in Ezra 9:6-15 compare structurally and theologically to Daniel''s prayer in Daniel 9?', 'Both are corporate confessional prayers structured around: acknowledgment of God''s righteousness, confession of specific sin, appeal to God''s covenant grace, and acknowledgment of deserved judgment; both also identify the exile as the consequence of the specific sins now being confessed', 'Ezra''s prayer is a legal brief while Daniel''s is a prophetic intercession — the two are structurally incompatible', 'Daniel''s prayer was more theologically developed since it cited specific covenant passages while Ezra''s was a personal emotional outburst', 'The two prayers cover different time periods and cannot be compared theologically since they address different aspects of the exile', 'a', 'Ezra 9:6 — "I am ashamed and blush to lift up my face...our iniquities are increased." Daniel 9:5-8 — "We have sinned, and have committed iniquity...O LORD, to us belongeth confusion of face." Both prayers begin with shame, confess corporate sin, acknowledge the exile as just, appeal to God''s mercy, and make no specific request — leaving the outcome entirely to God''s character. The structural parallel indicates a shared tradition of post-exilic covenantal confession.'),
('Ezra', 9, 'adults', 8, 'What does the final verse of Ezra''s prayer — "behold, we are before thee in our trespasses: for we cannot stand before thee because of this" (Ezra 9:15) — reveal about biblical confession and its relationship to hope?', 'By ending without a specific request, Ezra''s prayer throws the community entirely on God''s mercy rather than offering a negotiated solution — it is the most honest form of confession, acknowledging that the only remaining ground is God''s own righteousness, not human penitential achievement', 'The lack of a request shows Ezra had given up hope and was simply lamenting without expecting divine response', 'Ezra deliberately omitted a request because he planned to announce the specific remedy in chapter 10, making the prayer a rhetorical preparation rather than genuine intercession', 'The final verse shows Ezra believed the sin was unforgivable and the restoration was now permanently forfeit', 'a', 'Ezra 9:15 — "thou art righteous: for we remain yet escaped, as it is this day: behold, we are before thee in our trespasses: for we cannot stand before thee because of this." The prayer ends on God''s righteousness, not Israel''s penitence — the only possible foundation when guilt is acknowledged without reservation. Compare Psalm 130:3-4: "If thou, LORD, shouldest mark iniquities, O LORD, who shall stand? But there is forgiveness with thee."');

-- ═══ Ezra Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ezra', 10, 'kids', 1, 'Who made a speech to the weeping people and said there was hope for Israel if they put away their foreign wives?', 'Shechaniah the son of Jehiel', 'Ezra the scribe himself', 'Zerubbabel the governor', 'The high priest Jeshua', 'a', 'Ezra 10:2-3 — "Shechaniah the son of Jehiel...answered and said unto Ezra, We have trespassed against our God...Yet now there is hope in Israel concerning this thing. Now therefore let us make a covenant with our God to put away all the wives."'),
('Ezra', 10, 'kids', 2, 'Where did Ezra call all the people of Judah and Jerusalem to gather within three days?', 'Jerusalem', 'The river Ahava', 'The city of Bethlehem', 'The ruins of Jericho', 'a', 'Ezra 10:7 — "And they made proclamation throughout Judah and Jerusalem unto all the children of the captivity, that they should gather themselves together unto Jerusalem."'),
('Ezra', 10, 'kids', 3, 'What was the weather like when the people gathered at Jerusalem to deal with the problem of the foreign wives?', 'It was the ninth month and there was great rain', 'It was very hot in the summer harvest time', 'There was a great wind from the east that day', 'The snow had just fallen and the ground was frozen', 'a', 'Ezra 10:9,13 — "The people sat in the street of the house of God, trembling because of this matter, and for the great rain...Also the people are many, and it is a time of much rain."'),
-- Teens
('Ezra', 10, 'teens', 1, 'What was the penalty for anyone who did not come to Jerusalem within three days as Ezra had commanded?', 'All his substance should be forfeited and himself separated from the congregation of those that had been carried away', 'He should be put in prison until the matter was resolved', 'He should lose his land and be sent back to Babylon', 'He should be banned from the temple for one full year', 'a', 'Ezra 10:8 — "Whosoever would not come within three days, according to the counsel of the princes and the elders, all his substance should be forfeited, and himself separated from the congregation of the captivity."'),
('Ezra', 10, 'teens', 2, 'When Ezra stood before the gathered assembly, what did the people agree to do about the foreign wives?', 'We must put away all the wives and such as are born of them, according to the counsel of my LORD, and of those that tremble at the commandment of our God', 'They voted to let each man decide for himself whether to keep or dismiss his foreign wife', 'They agreed to require the foreign wives to convert before the month was over', 'They said only the priests must put away their wives but the common people could keep theirs', 'a', 'Ezra 10:3,12 — "let us make a covenant with our God to put away all the wives...and let it be done according to the law...Then all the congregation answered and said with a loud voice, As thou hast said, so must we do."'),
('Ezra', 10, 'teens', 3, 'How long did it take the judges to examine all the cases of men who had taken foreign wives?', 'From the first day of the tenth month unto the first day of the first month, three months', 'It took seven days with all the elders sitting in judgment', 'The matter was resolved in one day since the men confessed immediately', 'It took a full year to go through every case in every tribe', 'a', 'Ezra 10:16-17 — "Ezra the priest...separated themselves...and sat down in the first day of the tenth month to examine the matter. And they made an end with all the men that had taken strange wives by the first day of the first month."'),
('Ezra', 10, 'teens', 4, 'Among those who had taken foreign wives, which group was listed first and considered the most serious offenders?', 'The priests, sons of Jeshua and his brothers', 'The Levites and the singers', 'The princes and the nobles of Judah', 'The merchants and craftsmen who lived in the cities', 'a', 'Ezra 10:18 — "And among the sons of the priests there were found that had taken strange wives: namely, of the sons of Jeshua the son of Jozadak, and his brethren."'),
('Ezra', 10, 'teens', 5, 'What did the men who had taken foreign wives offer as part of their guilt before God?', 'They gave their hands that they would put away their wives, and being guilty they offered a ram of the flock for their trespass', 'They brought silver and gold to the temple treasury as a guilt offering', 'They fasted for seven days and made public confession before all Israel', 'They brought their foreign wives to the priests to be judged individually', 'a', 'Ezra 10:19 — "And they gave their hands that they would put away their wives; and being guilty, they offered a ram of the flock for their trespass."'),
-- Adults
('Ezra', 10, 'adults', 1, 'What is the theological significance of Shechaniah''s phrase "yet now there is hope in Israel" (Ezra 10:2) in the context immediately following Ezra''s devastating prayer?', 'It locates hope not in the community''s innocence but in the possibility of repentance and covenant renewal — the same God whose righteousness Ezra had just acknowledged (9:15) is also the God who accepts genuine repentance, making hope possible precisely when guilt is fully confessed', 'It was an expression of political optimism about Persia''s continued goodwill toward Israel', 'It referred to hope based on the numerical size of the returning community which could absorb the loss of some foreign wives', 'Shechaniah was overconfident and his hope was misplaced since the crisis was more serious than he understood', 'a', 'Ezra 9:15 ends with Israel''s guilt fully acknowledged; Ezra 10:2 immediately opens with "yet now there is hope." The structure is: honest confession → acknowledged guilt → hope through repentance. This is the pattern of Lamentations 3:22-23 — "It is of the LORD''s mercies that we are not consumed...Great is thy faithfulness."'),
('Ezra', 10, 'adults', 2, 'How does the covenant proposed in Ezra 10:3 — "to put away all the wives, and such as are born of them, according to the counsel of my Lord" — raise ethical tensions, and how has biblical scholarship addressed them?', 'It creates real ethical tension between covenant faithfulness (Malachi 2:16 — God hates divorce) and covenant purity (Deuteronomy 7:3-4 — no intermarriage with Canaanites); scholars note the text records the decision without explicit divine endorsement and the final book of Ezra does not narrate God''s blessing on the outcome', 'There is no ethical tension since the Torah explicitly commanded the dissolution of these marriages and Ezra was simply enforcing clear law', 'The marriages were annulled rather than divorced, so Malachi''s prohibition against divorce did not apply', 'The women were all returned to financially secure situations in their home communities, resolving any ethical concern about abandonment', 'a', 'Ezra 10:3 — "let us make a covenant with our God to put away all the wives." Malachi 2:16 — "For the LORD, the God of Israel, saith that he hateth putting away." The canon itself holds both texts in tension. Deuteronomy 7:3-4 prohibited intermarriage with Canaanite peoples; Ezra applied this principle in a post-exilic context. Ezra 10 is a historical narrative of a community decision, not a prescription endorsed by divine oracle in the text itself.'),
('Ezra', 10, 'adults', 3, 'What does the procedural arrangement in Ezra 10:14-17 — elders and judges examining each case individually over three months — reveal about the community''s approach to the crisis?', 'It shows the community pursued due process rather than mass summary action — each case was heard individually, allowing for varied circumstances, demonstrating that even in a community-wide covenant crisis, individual justice was preserved', 'It shows the elders were deliberately delaying the process hoping the community would abandon the covenant they had made', 'It reflects Persian administrative procedure for adjudicating domestic disputes in the province', 'It shows the community was overwhelmed and the three-month process was a sign of disorganisation rather than careful procedure', 'a', 'Ezra 10:14,17 — "let all them which have taken strange wives...come at appointed times, and with them the elders of every city and the judges thereof, until the fierce wrath of our God for this matter be turned from us...they made an end with all the men that had taken strange wives by the first day of the first month." The careful, individual process over 89 days shows pastoral sensitivity within a community-wide reform.'),
('Ezra', 10, 'adults', 4, 'How does the ending of the book of Ezra — with a bare list of offenders (Ezra 10:18-44) and no concluding blessing, prayer, or narrative resolution — shape the reader''s theological response?', 'The abrupt ending places the reader in the unresolved tension of the restoration: the community has acted with integrity but the outcome is not triumphant; sin has consequences that require painful ongoing work, and the story continues into Nehemiah without a neat closure — demanding continued engagement', 'The list of offenders is a literary mistake; the original ending was lost and the list is a later addition', 'The abrupt ending shows the author was hurried and the book is incomplete', 'The ending is deliberately understated to emphasise that obedience, not celebration, is the proper response to covenant renewal', 'a', 'Ezra 10:44 — "All these had taken strange wives: and some of them had wives by whom they had children." The book ends with ongoing pain — children involved, families disrupted — without theological resolution. This is honest narrative: covenant renewal is costly and incomplete. The continuation in Nehemiah suggests the author deliberately left the story open.'),
('Ezra', 10, 'adults', 5, 'What does the involvement of "all the congregation" in affirming the covenant to put away foreign wives (Ezra 10:12) reveal about the nature of covenant community in post-exilic Israel?', 'It shows that covenant faithfulness was not enforced top-down by Ezra alone but ratified by the whole community — the reform had authority because it was a communal decision, reflecting the Sinai covenant model where all Israel responded "all that the LORD hath spoken we will do"', 'It shows that Ezra used democratic pressure to force compliance with his personal religious agenda', 'It reflects Persian administrative protocol requiring community consent for any change in civic law', 'It shows the congregation was composed only of men since women had no covenant standing in post-exilic Israel', 'a', 'Ezra 10:12 — "Then all the congregation answered and said with a loud voice, As thou hast said, so must we do." Exodus 24:3 — "all the people answered with one voice, and said, All the words which the LORD hath said will we do." The communal response pattern of Ezra 10 deliberately echoes Sinai covenant ratification, presenting the reform as covenant renewal in the Mosaic tradition.'),
('Ezra', 10, 'adults', 6, 'How does the offering of a ram for trespass by the guilty men (Ezra 10:19) connect to the Levitical sacrificial system, and what does it reveal about the relationship between repentance, community action, and atonement?', 'The trespass offering (asham, Leviticus 5:15-16) was specifically designed for covenant violations involving sacred things — the men''s action in violating the holy seed (9:2) required both the communal covenant act (putting away wives) and the individual atoning sacrifice, showing that repentance had both horizontal and vertical dimensions', 'The ram offering was a voluntary additional gesture with no required Levitical basis', 'The trespass offering was made by the priests on behalf of all the people, not by the individual offenders themselves', 'The offering of rams preceded the putting away of wives, suggesting atonement could substitute for the community action', 'a', 'Ezra 10:19 — "they gave their hands that they would put away their wives; and being guilty, they offered a ram of the flock for their trespass." Leviticus 5:15 — "If a soul commit a trespass, and sin through ignorance, in the holy things of the LORD...he shall bring for his trespass unto the LORD a ram." The two acts together — the covenant commitment (giving their hands) and the sacrifice — demonstrate that genuine repentance involves both behavioural change and atonement before God.'),
('Ezra', 10, 'adults', 7, 'What is the relationship between Ezra 9-10 and Nehemiah 13, and what does the recurrence of the intermarriage problem reveal about the nature of covenant renewal?', 'Nehemiah 13:23-27 shows the same intermarriage problem recurring after Nehemiah''s reforms, demonstrating that institutional covenant renewal, however sincere, cannot permanently secure obedience — both texts together point toward the need for a new covenant written on the heart (Jeremiah 31:33)', 'The recurrence shows Ezra''s reform was ineffective and should have been more severe', 'The two texts are independent accounts of the same event at different periods, not sequential recurrences', 'Nehemiah 13 addresses only Levitical intermarriage; the problem Ezra addressed among the laity was successfully resolved by Ezra 10', 'a', 'Ezra 9-10 addresses intermarriage in the mid-5th century BC; Nehemiah 13:23-27 — "In those days also saw I Jews that had married wives of Ashdod, of Ammon, and of Moab" — shows the problem recurring under Nehemiah. The repetition across two reforms illustrates the prophetic diagnosis of Jeremiah 31:31-33: external covenant renewal cannot change the heart — only the new covenant written within can produce lasting obedience.'),
('Ezra', 10, 'adults', 8, 'How does the book of Ezra as a whole — from Cyrus''s decree (chapter 1) to the painful covenant renewal (chapter 10) — present a theology of restoration that is both genuine and incomplete?', 'The book shows that restoration is real (temple built, worship restored, Torah applied) but fragile (opposition arises, covenant is violated, reform must be repeated); it is genuine grace, not earned achievement, and it is incomplete, pointing forward to a fuller restoration beyond what human faithfulness can sustain', 'Ezra presents the restoration as complete and triumphant; the problems in chapters 9-10 are minor setbacks that do not affect the overall success', 'Ezra presents the restoration as fundamentally a political achievement under Persian patronage with theological language added by later editors', 'The book intentionally presents the restoration as a failure, justifying the expectation of a completely new redemptive act in the New Testament era', 'a', 'Ezra 1:1 (God''s word fulfilled through Cyrus) through 6:15 (temple completed) shows genuine restoration; Ezra 9:2 (holy seed mixed) and 10:44 (children involved, no neat resolution) shows its fragility. The book holds both truths: God''s covenant faithfulness is real and his purposes advance, but the human community repeatedly falls short — a tension that the prophets resolve only eschatologically (Ezekiel 36:26-27; Jeremiah 31:31-34).');

